-- Phase 1 (schema + seed): the sidequest content + quest data model.
--
-- ADDITIVE ONLY. This migration creates new tables, adds new nullable/defaulted
-- columns to `events`, and widens one CHECK. It never drops or rewrites existing
-- data. Paired revert: 20260619000000_quests_phase1_schema_and_seed.revert.sql
--
-- A "quest" is an `events` row (we overload events to reuse chat/attendance/venues
-- /costs). `quest_catalog` is the template library (the 165 seed sidequests).
-- `quest_tags` carries the matchable dimensions for a quest instance. `quest_ledger`
-- is the pairwise "you & them: N quests" retention artifact.

-- ============================================================================
-- 1. quest_catalog — the seed sidequest library (authenticated read-only)
-- ============================================================================
CREATE TABLE IF NOT EXISTS public.quest_catalog (
  id            bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  slug          text UNIQUE NOT NULL,
  title         text NOT NULL,
  dare          text NOT NULL,
  why           text,
  category      text NOT NULL,
  energy_level  smallint NOT NULL CHECK (energy_level BETWEEN 1 AND 3),
  social_mode   text NOT NULL CHECK (social_mode IN ('solo', 'pair', 'group', 'either')),
  duration_min  integer NOT NULL,
  cost_tier     smallint NOT NULL CHECK (cost_tier BETWEEN 0 AND 2),
  budget_min    numeric,
  budget_max    numeric,
  currency      text NOT NULL DEFAULT 'GBP',
  risk_tier     smallint NOT NULL DEFAULT 1 CHECK (risk_tier BETWEEN 1 AND 3),
  is_solo_safe  boolean NOT NULL DEFAULT true,
  vibe          text[] NOT NULL DEFAULT '{}',
  interests     jsonb NOT NULL DEFAULT '[]'::jsonb,  -- same array taxonomy as events.interests
  proof         text,
  safety_note   text,
  is_active     boolean NOT NULL DEFAULT true,
  created_at    timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.quest_catalog ENABLE ROW LEVEL SECURITY;
REVOKE ALL ON public.quest_catalog FROM anon;
GRANT SELECT ON public.quest_catalog TO authenticated;
CREATE POLICY "quest_catalog_authenticated_read"
  ON public.quest_catalog FOR SELECT TO authenticated USING (is_active);

-- ============================================================================
-- 2. events → overload into a quest instance (additive columns)
-- ============================================================================
ALTER TABLE public.events
  ADD COLUMN IF NOT EXISTS quest_catalog_id bigint REFERENCES public.quest_catalog(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS kind text NOT NULL DEFAULT 'open' CHECK (kind IN ('solo', 'open', 'crew')),
  ADD COLUMN IF NOT EXISTS status text NOT NULL DEFAULT 'active' CHECK (status IN ('active', 'completed', 'cancelled')),
  ADD COLUMN IF NOT EXISTS comfort smallint CHECK (comfort BETWEEN 1 AND 3),
  ADD COLUMN IF NOT EXISTS completed_at timestamptz;
-- Existing events become open, active quests — consistent with the reframe.

-- ============================================================================
-- 3. quest_tags — matchable dimensions for a quest instance (1:1 with events)
-- ============================================================================
CREATE TABLE IF NOT EXISTS public.quest_tags (
  event_id      bigint PRIMARY KEY REFERENCES public.events(id) ON DELETE CASCADE,
  vibe          text[] NOT NULL DEFAULT '{}',
  energy_level  smallint CHECK (energy_level BETWEEN 1 AND 3),
  social_mode   text CHECK (social_mode IN ('solo', 'pair', 'group', 'either')),
  duration_min  integer,
  risk_tier     smallint NOT NULL DEFAULT 1 CHECK (risk_tier BETWEEN 1 AND 3),
  is_solo_safe  boolean NOT NULL DEFAULT true,
  is_seed       boolean NOT NULL DEFAULT false,
  created_at    timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.quest_tags ENABLE ROW LEVEL SECURITY;
REVOKE ALL ON public.quest_tags FROM anon;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.quest_tags TO authenticated;
CREATE POLICY "quest_tags_authenticated_read"
  ON public.quest_tags FOR SELECT TO authenticated USING (true);
-- Only the host of the underlying event may write its tags (mirrors event_costs).
CREATE POLICY "quest_tags_host_manage"
  ON public.quest_tags FOR ALL TO authenticated
  USING (EXISTS (SELECT 1 FROM public.events e WHERE e.id = quest_tags.event_id AND e.user_id = auth.uid()))
  WITH CHECK (EXISTS (SELECT 1 FROM public.events e WHERE e.id = quest_tags.event_id AND e.user_id = auth.uid()));

-- ============================================================================
-- 4. quest_ledger — pairwise "you & them: N quests" (the retention artifact)
-- ============================================================================
CREATE TABLE IF NOT EXISTS public.quest_ledger (
  user_lo        uuid NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  user_hi        uuid NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  quest_count    integer NOT NULL DEFAULT 0,
  first_quest_at timestamptz,
  last_quest_at  timestamptz,
  PRIMARY KEY (user_lo, user_hi),
  CHECK (user_lo < user_hi)   -- canonical unordered pair ordering
);

ALTER TABLE public.quest_ledger ENABLE ROW LEVEL SECURITY;
REVOKE ALL ON public.quest_ledger FROM anon;
GRANT SELECT ON public.quest_ledger TO authenticated;
-- Read only the pairs you're part of. Writes happen via SECURITY DEFINER RPC (next migration).
CREATE POLICY "quest_ledger_read_own"
  ON public.quest_ledger FOR SELECT TO authenticated
  USING (auth.uid() = user_lo OR auth.uid() = user_hi);

-- ============================================================================
-- 5. reports.target_type — allow reporting a quest
-- ============================================================================
ALTER TABLE public.reports DROP CONSTRAINT IF EXISTS reports_target_type_check;
ALTER TABLE public.reports ADD CONSTRAINT reports_target_type_check
  CHECK (target_type IN ('user', 'message', 'event', 'conversation', 'quest'));

-- ============================================================================
-- 6. SEED — the 165 starter sidequests (generated from the ideation catalog)
-- ============================================================================
ON CONFLICT (slug) DO NOTHING;
