INSERT INTO public.quest_catalog (slug,title,dare,why,category,energy_level,social_mode,duration_min,cost_tier,budget_min,budget_max,currency,risk_tier,is_solo_safe,vibe,proof,safety_note) VALUES
('first-bus-no-plan','First Bus, No Plan','Walk to the nearest stop and board the first bus that pulls up. Ride it for 7 stops, get off, and just... be somewhere new. No map until you''re standing on the pavement. Where''d it spit you out?','The cheapest teleporter in your city is the one you''ve never thought to take. You''ll see a neighbourhood you''ve driven past a hundred times at 2 feet instead of 30mph.','Urban exploration & getting lost on purpose',1,'solo',90,1,1,15,'GBP',2,true,ARRAY['spontaneous','adventurous','outdoors','explore','solo-friendly'],'check-in at your drop-off point + one photo of where you landed','Stick to daylight for your first go, keep your phone charged, and screenshot the return route before you wander.'),
('the-coin-toss-walk','The Coin Toss Walk','Step outside. At every junction, flip a coin (or let the app flip): heads left, tails right. Follow fate for 20 minutes. Then find your way home WITHOUT the map. Trust your sense of direction. It''s worse than you think, and that''s the point.','Getting a little lost rewires how you hold a place in your head. You stop being a passenger in your own neighbourhood.','Urban exploration & getting lost on purpose',2,'solo',45,0,0,0,'GBP',2,true,ARRAY['spontaneous','adventurous','outdoors','explore','brave'],'drop a pin where you ended up + a one-line reflection on whether you panicked','Keep maps one tap away if you genuinely lose your bearings, and avoid this one after dark.'),
('look-up','Look Up','Pick a street you walk all the time. Walk it again, but spend the whole time looking ONLY above the ground floor: cornices, old signage ghosts, weird gargoyles, dates carved in stone. Photograph the strangest thing above eye level nobody else has noticed.','Cities hide their best stuff above the shopfronts. You''ve been staring at your feet for years.','Urban exploration & getting lost on purpose',1,'solo',30,0,0,0,'GBP',1,true,ARRAY['cozy','creative','outdoors','explore','nostalgic','low-effort'],'photo of your best ''above eye-level'' find',NULL),
('dead-end-hunter','Dead-End Hunter','Find a cul-de-sac, an alley, or a ''no through road'' you''ve never had a reason to enter, and go to the very end of it. Report back: what was hiding down there? A garden, a wall, a cat with strong opinions?','Dead ends are the parts of the map everyone skips. They''re where a city keeps its secrets and its weirdest front doors.','Urban exploration & getting lost on purpose',1,'pair',30,0,0,0,'GBP',2,false,ARRAY['spontaneous','explore','outdoors','curious','low-effort'],'photo from the dead end looking back the way you came','Public ways only: no climbing fences or entering private property or anywhere posted. If it feels off, turn around.'),
('highest-free-view-in-town','Highest Free View in Town','Quest: find the highest spot you can legally and freely reach, a multi-storey car park roof, a hill, a viewing deck, the top of a public stairwell, and watch your city from above for 10 minutes. No ticket required. Crown the best free skyline you find.','Seeing where you live from above completely rearranges your mental map. Suddenly the streets connect.','Urban exploration & getting lost on purpose',2,'group',90,0,0,0,'GBP',2,false,ARRAY['adventurous','outdoors','explore','social','scenic'],'photo of the view + check-in at your high point','Stay behind barriers, never near unguarded edges. Public, legal access only. Go with someone if you''re heading somewhere quiet.'),
('order-what-the-regular-orders','Order What the Regular Orders','Walk into the most unfamiliar cafe, bakery, or hole-in-the-wall you can find, somewhere you''d normally never stop, and order whatever the person ahead of you ordered. No menu peeking. Surrender to the regulars'' wisdom.','The best food in any city is the thing the locals order without thinking. This is how you find it, plus a tiny hit of bravery.','Urban exploration & getting lost on purpose',1,'pair',45,1,1,15,'GBP',2,false,ARRAY['spontaneous','cozy','social','explore','brave','foodie'],'photo of what you ended up with + verdict (would you order it again?)','Heads up if you have allergies, ask what''s in it before you commit.'),
('tourist-in-your-own-postcode','Tourist In Your Own Postcode','Pretend you flew in this morning and your home street is the destination. Find three things a visitor would photograph within a 10-minute walk that you''ve completely stopped seeing. Be insufferable about it. Take the photos.','Familiarity is a blindfold. This rips it off and hands your own neighbourhood back to you like it''s brand new.','Urban exploration & getting lost on purpose',1,'pair',45,0,0,0,'GBP',1,false,ARRAY['nostalgic','creative','explore','outdoors','cozy','low-effort'],'your three ''tourist'' photos',NULL),
('follow-the-music','Follow the Music','Head out and walk toward any sound that isn''t traffic, a busker, church bells, a market, distant laughter, a dog you can''t see yet. Let your ears lead instead of your phone. Find the source and tell us what it was.','We navigate by screens now. Navigating by sound for a while is strange, lovely, and slightly feral in the best way.','Urban exploration & getting lost on purpose',2,'pair',45,0,0,0,'GBP',2,false,ARRAY['spontaneous','creative','outdoors','explore','curious'],'audio clip or photo of the source + check-in','Daytime is best, and stay aware of crossings and traffic while your attention''s on the sound.'),
('the-5-stranger-smile-run','The 5-Stranger Smile Run','Take a walk through a busy part of town and make genuine eye contact and smile (or nod) at five different strangers. Notice how many smile back. Bonus side-quest: one real ''lovely day, isn''t it'' to a shopkeeper.','Cities feel anonymous because we make them that way. Five small connections changes how a whole street feels, including for you.','Urban exploration & getting lost on purpose',1,'solo',30,0,0,0,'GBP',2,true,ARRAY['social','brave','spontaneous','outdoors','kind'],'reflection: how many smiled back, and how it felt','Friendly, brief, public-space only. Read the room and don''t pursue anyone who isn''t keen; a non-response is just a no.'),
('night-lights-loop','Night Lights Loop','After dark, take a lit, lively route through town and hunt the best-glowing thing you can find: neon, a floodlit building, reflections in wet pavement, a shop window someone clearly loved decorating. Bring back the most beautiful light in your city tonight.','Your town has a whole second personality after sunset. Most people never go looking for it.','Urban exploration & getting lost on purpose',2,'group',90,0,0,0,'GBP',2,false,ARRAY['adventurous','creative','outdoors','explore','scenic','social'],'photo of the best light + check-in','Do this with a friend, stick to well-lit, busy streets, share your location with someone, and skip isolated areas. Set the comfort dial accordingly.'),
('pick-a-door-you-ll-never-use','Pick a Door You''ll Never Use','Find a public building you''ve genuinely never been inside, a library, a museum, an old church, a town hall, a gallery, and just walk in for 15 minutes. No agenda. See what''s behind the door you''ve passed a thousand times.','There''s a building you''ve walked past your whole life and assumed wasn''t ''for you''. It almost certainly is, and it''s free.','Urban exploration & getting lost on purpose',1,'pair',45,0,0,0,'GBP',2,false,ARRAY['cozy','explore','nostalgic','curious','low-effort','indoors'],'check-in at the building + one thing you found inside','Check opening hours so you''re not arriving to a locked door.'),
('two-stops-past-normal','Two Stops Past Normal','Next time you''re on a train or tram, ride two stops past where you''d normally get off. Explore that area for half an hour like it was the plan all along, then make your way back. Claim a new stop as ''yours''.','The edges of your routine are the easiest frontier you''ve got. Two stops is barely a detour and a whole new corner of the map.','Urban exploration & getting lost on purpose',1,'solo',90,1,1,15,'GBP',2,true,ARRAY['spontaneous','explore','outdoors','adventurous','low-effort'],'check-in at the new stop + photo of one good thing you found','Mind the last departure time so you''re not stranded, and stick to daylight for somewhere unfamiliar.'),
('the-mystery-pin-meetup','The Mystery Pin Meetup','As a crew, let one person drop a pin somewhere none of you have been, a park, a market, a random square, and all converge on it by whatever route you fancy. First to arrive picks where you go next. Explore from there together.','Splitting up and reuniting somewhere new turns a normal hangout into a tiny expedition. The group chat finally goes somewhere.','Urban exploration & getting lost on purpose',3,'group',60,1,1,15,'GBP',2,false,ARRAY['social','adventurous','explore','outdoors','spontaneous','crew'],'group photo at the pin + everyone checks in','Pick a public, well-populated meeting point and share live locations so nobody''s wandering alone if they get turned around.'),
('trace-a-river-or-a-train-line','Trace a River (or a Train Line)','Find a river, canal, or railway line near you and follow it on foot in one direction for as long as you fancy, using it as your only guide. Cities grow along these threads. See where yours leads. Turn back whenever you like.','Following water or rails is the oldest way to read a city. You''ll stitch together parts of town you never knew touched.','Urban exploration & getting lost on purpose',3,'pair',60,0,0,0,'GBP',2,false,ARRAY['adventurous','outdoors','explore','scenic','active'],'check-in at your turnaround point + a photo from the path','Stay on public, marked towpaths and paths, never on or beside live tracks. Watch footing near water and go with someone for longer stretches.'),
('the-genuine-compliment-drop','The Genuine Compliment Drop','Spot one stranger today and tell them something true you actually noticed — the jacket, the laugh, the way they handled a chaotic toddler. No agenda, no follow-up. Drop it and keep walking. Watch their whole face change.','A specific compliment from a stranger is a rare, weightless gift. Costs you ten seconds and rewires someone''s afternoon — yours included.','Talk to strangers & micro-connection',1,'solo',15,0,0,0,'GBP',2,true,ARRAY['spontaneous','social','brave','kind','warm'],'reflection','Keep it about something they chose (clothes, a skill, energy) — never their body. Read the room; if they''re rushing or uneasy, let it go.'),
('ask-the-barista-a-real-question','Ask The Barista A Real Question','Next coffee run, ditch the autopilot ''how''s your day.'' Ask the person making your drink one actual question — busiest hour, weirdest order ever, the song stuck in their head. Stay for the answer.','The people who serve you all day get treated like vending machines. Two real sentences turns a transaction into a tiny moment of being human at each other.','Talk to strangers & micro-connection',1,'solo',15,1,1,15,'GBP',2,true,ARRAY['spontaneous','social','cozy','warm','kind'],'reflection','Mind the queue behind you — read whether they''ve got time to chat or need to keep the line moving.'),
('the-recommendation-heist','The Recommendation Heist','Walk into a bookshop, record store, plant shop, or deli and ask a stranger — not the staff, a fellow customer — what YOU should get. Take their pick. Actually buy it. You now own a stranger''s taste.','Letting a random human curate your life for five minutes is delightfully low-stakes chaos, and you''ll have a story attached to whatever you walk out with.','Talk to strangers & micro-connection',2,'solo',30,1,1,15,'GBP',2,true,ARRAY['spontaneous','adventurous','social','creative','brave'],'photo','Stay in the public, staffed space. If someone declines, that''s a no — thank them and ask the next person.'),
('two-truths-to-a-stranger','Two Truths To A Stranger','Find someone waiting for the same thing you are — bus, elevator, the slow microwave at work — and start a thirty-second conversation that goes one layer past small talk. Skip the weather. Ask what they''re looking forward to this week.','Most ''awkward'' silences are just two people both wishing the other would start. Be the one who starts. The waiting time becomes the good part.','Talk to strangers & micro-connection',1,'solo',15,0,0,0,'GBP',2,true,ARRAY['spontaneous','social','brave','warm'],'reflection','Public, populated spots only. Gracefully exit if they put headphones in or give one-word answers — not everyone''s in the mood, and that''s fine.'),
('pay-it-backward','Pay It Backward','Cover the order of the person behind you in line — coffee, toll, snack, whatever. Don''t stick around for thanks. Just leave a little ripple in someone''s morning and slip out.','Anonymous generosity hits different. No reward loop, no awkwardness, just the quiet thrill of knowing you made a stranger''s day mildly inexplicable and better.','Talk to strangers & micro-connection',1,'solo',15,1,1,15,'GBP',2,true,ARRAY['spontaneous','kind','social','warm'],'check-in','Keep it small and within your budget — generosity shouldn''t cost you a meal.'),
('the-dog-is-the-icebreaker','The Dog Is The Icebreaker','See a good dog in public? Ask the owner the dog''s name and one thing about it. Congratulations, you have now had a conversation. The dog did all the work.','Pets are nature''s social lubricant. This is the lowest-pressure entry into talking to a stranger that exists, and dog people love being asked.','Talk to strangers & micro-connection',1,'solo',15,0,0,0,'GBP',2,true,ARRAY['spontaneous','outdoors','social','cozy','warm'],'photo','Ask before touching the dog — some are nervous or working. The owner''s the boss here.'),
('crew-compliment-run','Crew Compliment Run','Grab a friend, hit a busy street or market, and challenge each other: who can spark a genuine thirty-second exchange with a stranger first? Loser buys the next round. Cheer each other on like absolute goblins.','Bravery is contagious and way easier with a wingman. Turn the scariest version of this into a giggling competition and the fear just evaporates.','Talk to strangers & micro-connection',2,'pair',60,1,1,15,'GBP',2,false,ARRAY['spontaneous','social','brave','adventurous','playful'],'witness','Daytime, busy public areas. Don''t corner anyone or make it a spectacle at a stranger''s expense — the joke is on your nerves, not on them.'),
('trade-three-songs','Trade Three Songs','Tell a stranger you''re building the world''s most chaotic playlist and you need one song from them — the one they''d put on at 2am. Offer one of yours back. Walk away with a track you''d never have found.','Music is the fastest shortcut to who someone actually is. You''ll leave with a new favorite song AND the face of the person who gave it to you.','Talk to strangers & micro-connection',2,'solo',30,0,0,0,'GBP',2,true,ARRAY['spontaneous','creative','social','nostalgic','brave'],'reflection','Public setting; a quick exchange, not a request for their number. Let them write it down or just say it aloud.'),
('become-a-regular-tonight','Become A Regular Tonight','Post up at a bar, café counter, or low-key local spot solo. Strike up one conversation with whoever''s next to you. Stay long enough to learn their name and one story. Leave when it''s natural, not when it''s awkward.','There''s a specific magic to talking to a stranger you''ll probably never see again — total honesty, zero stakes. This is how every ''you won''t believe who I met'' story begins.','Talk to strangers & micro-connection',2,'solo',60,2,20,60,'GBP',2,true,ARRAY['spontaneous','social','brave','adventurous','cozy'],'reflection','Night + strangers + alcohol: tell someone where you are, watch your drink, keep your own tab, and trust your gut — a graceful exit is always available. Pace the drinks.'),
('the-lost-tourist-rescue','The Lost Tourist Rescue','Find someone who looks lost — squinting at a map, spinning a phone around — and offer to help before they ask. Bonus points if you walk them halfway there and recommend your favorite nearby spot.','Being the local hero for thirty seconds feels weirdly great, and you get to brag about your neighborhood to someone who''s actually impressed.','Talk to strangers & micro-connection',1,'solo',15,0,0,0,'GBP',2,true,ARRAY['spontaneous','kind','social','outdoors','warm'],'reflection','Point the way or walk a short public stretch — don''t get into vehicles or lead anyone somewhere isolated. Offer help, don''t insist.'),
('borrow-a-life-story','Borrow A Life Story','Talk to someone who''s clearly older than you — a neighbor, a regular at the park, the person on the next bench — and ask them one thing: what''s the best decision they ever made. Then just listen. Don''t fill the silence.','People are walking libraries and almost nobody asks to read them. The answers are usually free, surprising, and impossible to get from a screen.','Talk to strangers & micro-connection',1,'solo',30,0,0,0,'GBP',2,true,ARRAY['social','nostalgic','warm','kind','cozy'],'reflection','Public, comfortable settings like a park or community space. Let them steer how much they share — listening is the whole point.'),
('host-the-stranger-table','Host The Stranger Table','At a packed café or food hall where seats are scarce, be the one who says ''there''s room here.'' Invite a seat-hunting stranger to share your table — then actually talk to them instead of both pretending to scroll.','You turn the most British thing (sitting in silence near someone) into an open invitation. Half the time you get a great chat; the other half you just made someone''s lunch less lonely.','Talk to strangers & micro-connection',2,'either',30,1,1,15,'GBP',2,true,ARRAY['spontaneous','social','warm','kind','cozy','brave'],'reflection','Busy public venue only. A shared table is an offer, not an obligation — if they''d rather sit quietly, let them, no pressure.'),
('pocket-poem-drop','Pocket Poem Drop','Write a four-line poem about a total stranger you can see right now — the guy guarding his laptop like it''s gold, the woman laughing too loud. Don''t show them. Just capture them. Bonus points if it rhymes badly on purpose.','Forces you to actually look at people instead of scrolling past them. You''ll never see a coffee shop the same way again.','Creative & self-expression',1,'solo',20,0,0,0,'GBP',2,true,ARRAY['creative','cozy','low-key','observant','writing'],'reflection (paste the poem)','Keep it kind and keep it private — don''t photograph or approach the person you wrote about.'),
('one-object-ten-photos','One Object, Ten Photos','Pick the most boring object near you — a spoon, a doorknob, your shoe. Now shoot it ten completely different ways. Weird angles, shadows, reflections, extreme close-ups. Make the dull thing look like it belongs in a gallery.','Constraints unlock creativity. Ten photos of one nothing-object teaches you more about seeing than ten photos of ten pretty things.','Creative & self-expression',1,'solo',30,0,0,0,'GBP',1,true,ARRAY['creative','cozy','photography','low-key','playful'],'photo (your favourite of the ten)',NULL),
('cook-something-with-no-recipe','Cook Something With No Recipe','Open the fridge. Make a meal using only what''s already in there — no Googling, no recipe, no safety net. Name your creation something ridiculous and plate it like you''re charging £18 for it.','Improvising dinner is low-stakes creative courage, and you might accidentally invent your new favourite thing.','Creative & self-expression',2,'solo',60,0,0,0,'GBP',1,true,ARRAY['creative','cozy','playful','homebound','food'],'photo of the finished (named) dish',NULL),
('chalk-a-compliment','Chalk a Compliment','Grab a stick of pavement chalk and leave one anonymous, genuinely nice message somewhere a stranger will find it tomorrow. ''You''re doing better than you think.'' Then walk away before anyone sees you.','You''ll make a stranger''s morning and feel weirdly powerful about it. Anonymous kindness is the best kind of mischief.','Creative & self-expression',2,'solo',30,1,1,15,'GBP',2,true,ARRAY['creative','kind','outdoors','playful','brave'],'photo of your chalk message','Use washable chalk on public pavement only — never private property, and not on walls or anything that doesn''t wash off in the rain.'),
('sketch-the-person-across-from-you','Sketch the Person Across From You','You and a friend, pens out, 90 seconds on the clock. Draw each other without looking down at the paper — eyes on the face the whole time. Reveal at the same moment. The worse it looks, the better.','Blind contour drawing is impossible to do well and impossible to do without laughing. Pure connection, zero skill required.','Creative & self-expression',1,'pair',15,0,0,0,'GBP',1,false,ARRAY['creative','social','playful','cozy','low-key'],'photo of both drawings side by side',NULL),
('soundtrack-a-stranger','Soundtrack a Stranger','Sit somewhere public. Watch one person going about their business and, in your head, score their life like a film. Then build a 5-track playlist that IS that person. Title it after them (''Man Who Definitely Owns a Boat'').','It turns people-watching into worldbuilding, and you''ll end up with a genuinely interesting playlist you''d never have made.','Creative & self-expression',1,'solo',30,0,0,0,'GBP',2,true,ARRAY['creative','cozy','music','observant','low-key'],'reflection (share the playlist title + tracks)','Watch discreetly and stay respectful — no following, no photos, just imagination.'),
('collaborative-story-one-line-each','Collaborative Story, One Line Each','Start a story with one sentence. Pass the phone to whoever you''re with. They add one line, pass it back. Keep going until it''s gloriously unhinged or someone cries laughing. Read the whole thing aloud at the end.','Nobody controls the plot, so it goes places no single brain would. The reading-aloud part is where the magic detonates.','Creative & self-expression',2,'group',30,0,0,0,'GBP',1,false,ARRAY['creative','social','playful','writing','cozy'],'reflection (paste the final story)',NULL),
('dress-for-a-theme-nobody-knows','Dress For a Theme Nobody Knows','Pick a secret theme for your outfit today — ''retired pirate'', ''main character in a French film'', ''detective who''s given up''. Wear it fully. Tell no one. Move through your whole day in character-adjacent.','Private performance is the purest self-expression — no audience, no judgement, just you committing to a bit for yourself.','Creative & self-expression',2,'solo',60,0,0,0,'GBP',1,true,ARRAY['creative','playful','brave','self-expression','fashion'],'photo of the fit + reveal the secret theme',NULL),
('found-object-tiny-sculpture','Found-Object Tiny Sculpture','On your next walk, collect five things off the ground — a leaf, a bottlecap, a stray bolt, whatever. Get home and assemble them into one tiny sculpture. Give it a name and a backstory.','Turning litter and twigs into something deliberate is sneakily meditative, and it makes a walk feel like a treasure hunt.','Creative & self-expression',2,'solo',45,0,0,0,'GBP',2,true,ARRAY['creative','outdoors','playful','low-key','nostalgic'],'photo of the sculpture','Only pick up things that are clean and safe to handle — skip anything sharp, broken-glass, or grim.'),
('record-a-voice-memo-to-future-you','Record a Voice Memo To Future You','Hit record. Talk to yourself one year from now for two minutes — what you''re scared of, hoping for, secretly proud of. No script, no editing, no deleting. Save it where you''ll find it next year.','It''s a time capsule in your own voice. Future-you will be floored by how much has changed — and how much hasn''t.','Creative & self-expression',1,'solo',15,0,0,0,'GBP',1,true,ARRAY['creative','reflective','cozy','nostalgic','self-expression'],'check-in (confirm it''s recorded + saved)',NULL),
('open-mic-no-backing-out','Open Mic, No Backing Out','Find a local open mic this week and put your name down for ONE thing — a song, a poem, a two-minute bit, reading something you wrote. The shaking hands are part of the deal. Do it anyway.','The terror is the point. Almost nothing beats the high of having actually done the scary creative thing in front of strangers.','Creative & self-expression',3,'either',60,1,1,15,'GBP',2,true,ARRAY['creative','brave','social','adventurous','performance'],'witness (or a clip a friend films) + reflection on how it felt','Pick a reputable venue, tell someone where you''ll be, and ideally bring a friend — open mics are often at night.'),
('paint-with-your-wrong-hand','Paint With Your Wrong Hand','Grab any paint, pen, or even ketchup and make a piece of art using only your non-dominant hand. No fixing it, no starting over. Lean all the way into the wobbly chaos.','It silences your inner critic instantly — you literally can''t be precious about it. Wonky art is the most honest art.','Creative & self-expression',1,'solo',30,1,1,15,'GBP',1,true,ARRAY['creative','playful','cozy','low-key','homebound'],'photo of the finished piece',NULL),
('redesign-your-street','Redesign Your Street','Walk your own street like you''ve never seen it. Photograph three things that are ugly or broken, then sketch or describe how you''d fix them. Tiny park here. Mural there. You''re the city planner now.','It rewires how you see your everyday route from ''background'' to ''mine to imagine''. Suddenly the dull walk home has potential.','Creative & self-expression',2,'pair',45,0,0,0,'GBP',2,false,ARRAY['creative','outdoors','observant','social','adventurous'],'photo of a ''before'' + reflection on your redesign','Photograph public spaces and streets, not people''s windows or homes — keep it about the place.'),
('make-a-zine-in-an-hour','Make a Zine in an Hour','One sheet of paper, folded into a mini 8-page booklet (Google ''one page zine fold''). Fill it with anything — your week, your hot takes, drawings of every dog you saw today. Done in an hour, no perfectionism allowed.','A finished tiny thing beats a perfect unfinished one every time. By the end you''ll have a real object you made from nothing.','Creative & self-expression',2,'solo',60,0,0,0,'GBP',1,true,ARRAY['creative','cozy','writing','playful','homebound'],'photo of the finished zine (a page or two)',NULL),
('coin-flip-wander','Coin-Flip Wander','Step outside with no destination. At every corner, flip a coin (or just guess heads): heads turn left, tails turn right. Follow it for 20 minutes, then find your way back. The map app is for cowards.','Your own neighbourhood is a stranger when you stop steering. Tiny act, surprisingly big reset.','Adventure & gentle adrenaline',1,'solo',40,0,0,0,'GBP',2,true,ARRAY['spontaneous','adventurous','outdoors','solo-ok'],'check-in at your turnaround point + one photo of wherever the coin abandoned you','Stick to areas you''d happily walk in normal daylight. Share your live location with a friend if you''re somewhere unfamiliar.'),
('the-stranger-bus','The Stranger Bus','Hop on the next bus or tram that pulls up. Ride it to a stop you''ve never gotten off at. Get out, look around, find one good thing, then make your way home however you like.','All the romance of getting lost in a new city, except it''s the city you already live in.','Adventure & gentle adrenaline',1,'solo',60,1,1,15,'GBP',2,true,ARRAY['adventurous','spontaneous','outdoors','explore'],'photo of the unfamiliar stop sign or street + a one-line note on the good thing you found','Keep enough charge/fare to get back, and avoid this one late at night in areas you don''t know.'),
('cold-plunge-dare','Cold Plunge Dare','End your next shower with 30 seconds of fully cold water. No easing in, no negotiating. Gasp, swear, survive. Tomorrow, go for 60.','The smallest, safest way to prove to yourself you can do the thing your body is begging you not to.','Adventure & gentle adrenaline',2,'solo',10,0,0,0,'GBP',2,true,ARRAY['brave','adventurous','energising','quick'],'reflection: rate how alive you felt 1-10 right after','Skip if you have heart issues, are pregnant, or have a condition affected by cold-water shock. Don''t do this in open water alone.'),
('golden-hour-summit','Golden Hour Summit','Find the highest reachable point near you, a hill, a rooftop bar, a multi-storey car park''s top deck, and get there for sunset. Watch the whole thing. Don''t film all of it.','There''s a height near you that turns your boring town into a postcard. You''ve just never bothered to climb it.','Adventure & gentle adrenaline',2,'pair',60,1,1,15,'GBP',2,false,ARRAY['adventurous','outdoors','cozy','social','golden-hour'],'photo of the view at sunset, with a friend in frame if you brought one','Only go where you''re actually allowed to be, no fences, no roofs that aren''t yours. Bring a layer; it gets cold once the sun drops.'),
('dare-a-friend-pick-the-trail','Dare a Friend, Pick the Trail','Text a friend right now: ''Pick a walking route neither of us has done. I''ll meet you Saturday.'' They choose, you both show up, no opting out. Loser of who-arrives-last buys the post-walk coffee.','The ''we should go for a walk sometime'' that''s been rotting in your chat for months. This is sometime.','Adventure & gentle adrenaline',2,'pair',60,1,1,15,'GBP',2,false,ARRAY['adventurous','social','outdoors','spontaneous'],'both of you check in at the trailhead + a photo somewhere along the route','Tell someone your route and rough return time if it''s a remote or rural trail.'),
('yes-hour','Yes Hour','For one hour, say yes to every reasonable thing offered to you, a sample, an invite, a ''wanna check this out?'', a different route home. Keep a tally. See where yes drags you.','Most of your life is no on autopilot. One hour of yes is a controlled experiment in being a more interesting person.','Adventure & gentle adrenaline',1,'either',60,0,0,0,'GBP',2,true,ARRAY['spontaneous','brave','playful','social'],'reflection listing every yes and the best place one of them led','''Reasonable'' is doing the heavy lifting here, you keep full veto over anything unsafe, expensive, or that gives you the ick. Yes is a game, not an obligation.'),
('night-walk-no-headphones','Night Walk, No Headphones','After dark, take a 25-minute walk with your phone in your pocket and nothing in your ears. Just you, the quiet streets, and whatever the night sounds like.','The night version of your street is a different planet. Gentle bravery, zero adrenaline crash.','Adventure & gentle adrenaline',1,'solo',40,0,0,0,'GBP',2,true,ARRAY['brave','outdoors','cozy','reflective','nighttime'],'reflection: one thing you heard or noticed that you''d have missed with earbuds in','Stay on well-lit, populated routes you know. Tell someone you''re heading out, and trust your gut, turn back any time it doesn''t feel right.'),
('borrow-a-beginner-sport','Borrow a Beginner Sport','Book a single drop-in session of a sport you''ve never tried, bouldering, kayaking, a skate lesson, archery. One go. No commitment, no gear-buying spiral. Just turn up and be hilariously bad at it.','Being a complete beginner at something physical is humbling, thrilling, and the fastest cure for taking yourself too seriously.','Adventure & gentle adrenaline',3,'pair',60,2,20,60,'GBP',2,false,ARRAY['adventurous','brave','active','social','try-new-thing'],'photo from the session, ideally mid-flail','Use a proper venue with instructors and safety gear. Tell them honestly it''s your first time.'),
('crew-scavenger-sprint','Crew Scavenger Sprint','Round up your group. Each person secretly writes one ''find/photograph this'' challenge into a hat (a red door, a stranger''s dog, the oldest building on the block). Set a 45-minute timer, split up, race to clear the whole list.','It turns a flat afternoon with your friends into a frantic, laughing competition that you''ll be quoting for weeks.','Adventure & gentle adrenaline',3,'group',60,0,0,0,'GBP',2,false,ARRAY['adventurous','social','playful','outdoors','group'],'the group''s combined photo grid of every item found','Always ask before photographing strangers or their pets. Agree a meet-back spot and keep the group reachable.'),
('order-the-mystery','Order the Mystery','Walk into a food spot you''ve never tried, ideally one with a cuisine you can''t pronounce, and order the one thing on the menu you don''t recognise. No googling first. Eat it like you meant to.','Low-stakes bravery with a delicious failure rate. Worst case, a funny story; best case, your new favourite meal.','Adventure & gentle adrenaline',1,'pair',60,1,1,15,'GBP',2,false,ARRAY['adventurous','spontaneous','playful','social','food'],'photo of the mystery dish + your verdict in one word','Flag any allergies to staff before you order, mystery is fun, anaphylaxis is not.'),
('sunrise-mission','Sunrise Mission','Set an alarm for ungodly o''clock and be outside, somewhere with a view east, before the sun comes up. Watch it rise. Get a coffee. Be smug about it all day.','Almost nobody is awake for this and that''s exactly why it feels like you stole something from the day.','Adventure & gentle adrenaline',2,'pair',60,1,1,15,'GBP',2,false,ARRAY['adventurous','brave','outdoors','cozy','early-bird'],'timestamped photo of the sunrise (the timestamp is the whole point)','If you''re heading out pre-dawn alone, pick a place that won''t be deserted and let someone know your plan.'),
('detour-home','Detour Home','On your next trip home, get off one stop early or take a deliberately wrong turn. Spend the extra 15 minutes exploring the bit of your route you always blow past.','Adventure doesn''t always need a plan and a backpack. Sometimes it''s the corner you''ve ignored a thousand times.','Adventure & gentle adrenaline',1,'solo',30,0,0,0,'GBP',1,true,ARRAY['spontaneous','adventurous','outdoors','quick','everyday'],'photo of something on the detour you''d never noticed before',NULL),
('pin-drop-picnic','Pin-Drop Picnic','Drop a random pin within a reasonable distance, close your eyes, point at the map, whatever. Pack a snack, get yourselves there, and have a tiny picnic wherever fate landed you, even if it''s a weird bench by a roundabout.','The dumber the location, the better the memory. A perfect park is forgettable; a picnic by a roundabout is legend.','Adventure & gentle adrenaline',2,'group',60,1,1,15,'GBP',2,false,ARRAY['adventurous','spontaneous','social','outdoors','playful'],'group photo at the pinned spot, no matter how unglamorous','Sanity-check the pin before committing, skip private land, dodgy spots, or anywhere you can''t legally sit.'),
('talk-to-the-local','Talk to the Local','Strike up one genuine conversation with someone whose job is to know the area, a barista, a shopkeeper, a market seller. Ask them their single favourite hidden spot nearby. Then go there.','The best places are never on the map. They''re in the head of the person who''s worked the corner for ten years.','Adventure & gentle adrenaline',2,'solo',60,0,0,0,'GBP',2,true,ARRAY['brave','adventurous','social','explore','spontaneous'],'check-in at the recommended spot + a note on who sent you there','Read the room, keep it friendly and brief, and don''t push if they''re busy or not up for chatting.'),
('pay-it-backward-2','Pay It Backward','Next coffee, tea, or snack run: quietly cover the order for whoever''s behind you in line. No name, no speech, no lingering for applause. Pay and bounce. Let them figure it out.','The cleanest hit of anonymous-giving dopamine there is. You''ll think about the stranger''s confused little smile all day.','Acts of kindness & wholesome',1,'solo',30,1,1,15,'GBP',1,true,ARRAY['wholesome','kindness','spontaneous','generous','feel-good'],'photo of the receipt or a quick reflection on how it felt',NULL),
('the-3-person-text','The 3-Person Text','Text three people something specific you''ve never told them: not ''thanks for everything'' but ''I still think about the time you stayed up with me.'' Be precise. Watch the group chat detonate with feelings.','Specific gratitude lands ten times harder than generic. You''ll make someone''s entire week from your couch.','Acts of kindness & wholesome',1,'solo',15,0,0,0,'GBP',1,true,ARRAY['wholesome','kindness','cozy','nostalgic','connection'],'reflection on which reply hit hardest',NULL),
('sidewalk-treasure-drop','Sidewalk Treasure Drop','Leave a small surprise where someone will stumble on it: a wrapped snack on a park bench, a ''you''ve got this'' note tucked into a library book, a flower on a windshield. Tiny gift, big stranger-day-upgrade.','You become a friendly ghost. Someone''s ordinary Tuesday gets a little plot twist, and they''ll never know it was you.','Acts of kindness & wholesome',2,'solo',45,1,1,15,'GBP',2,true,ARRAY['wholesome','kindness','creative','spontaneous','outdoors'],'photo of the drop in place (no faces)','Leave only safe, clearly harmless items, and don''t tuck anything into cars or private property in a way that looks suspicious.'),
('adopt-a-lonely-plant','Adopt a Lonely Plant','Spot the saddest neglected plant in your orbit (office, hallway, a friend''s windowsill) and quietly nurse it back to life. Water, light, a little pep talk. Become its anonymous guardian.','Low-key, deeply soothing, and weirdly meditative. Kindness doesn''t always need a human on the other end.','Acts of kindness & wholesome',1,'solo',30,0,0,0,'GBP',1,true,ARRAY['wholesome','kindness','cozy','nurturing','calm'],'before/after photo of your patient',NULL),
('tip-like-a-legend','Tip Like a Legend','Someone''s doing a thankless job near you right now: barista, bus driver, the person restocking shelves at 9pm. Tip big or just say one genuine, specific thing about how they made your day easier. Mean it.','Service workers run on autopilot through a hundred ignored faces. Being actually seen for ten seconds is a real gift.','Acts of kindness & wholesome',1,'solo',10,1,1,15,'GBP',1,true,ARRAY['wholesome','kindness','spontaneous','social','generous'],'reflection or a quick check-in',NULL),
('two-person-cause-run','Two-Person Cause Run','Grab a friend and knock out one tiny good deed together: donate a bag of clothes, fill a little free pantry, walk a shelter dog. Pick the cause in five minutes, do it in an hour, debrief over snacks.','Doing good with someone turns a chore into a memory. You''ll both leave lighter and have a story you made on purpose.','Acts of kindness & wholesome',2,'pair',60,1,1,15,'GBP',1,false,ARRAY['wholesome','kindness','social','outdoors','connection'],'photo of the two of you mid-deed',NULL),
('reverse-compliment-ambush','Reverse Compliment Ambush','Hand out three real compliments to three strangers today, in person. Not the body, the choices: ''that jacket is a power move,'' ''your laugh just fixed my whole morning.'' Drop it, smile, keep walking.','It''s a tiny act of bravery that costs nothing and rewires how you see crowds. People light up when it''s clearly sincere.','Acts of kindness & wholesome',2,'solo',30,0,0,0,'GBP',2,true,ARRAY['wholesome','kindness','brave','social','spontaneous'],'reflection on the best reaction you got','Keep compliments about choices/vibe, never appearance in a way that could read as a come-on, and read the room. If someone seems uncomfortable, smile and move on.'),
('bring-back-the-handwritten-note','Bring Back the Handwritten Note','Write one actual paper note by hand and physically deliver it. Thank a neighbor, surprise a coworker, leave it on the kitchen table. Pen, paper, no emojis to hide behind. Words that someone can keep in a drawer for years.','In a world of instant texts, a handwritten note is almost shockingly intimate. People save these forever.','Acts of kindness & wholesome',1,'solo',30,0,0,0,'GBP',1,true,ARRAY['wholesome','kindness','nostalgic','creative','cozy'],'photo of the note before you hand it over',NULL),
('be-the-helper-hands','Be the Helper Hands','Catch one stranger struggling today and just step in: carry the heavy bag up the stairs, help fold the stroller, hold the door for the person with their arms full. See the need, fill it, no fuss.','Most people freeze and assume someone else will help. Be the one who actually moves. It''s the most human kind of magic.','Acts of kindness & wholesome',2,'solo',15,0,0,0,'GBP',2,true,ARRAY['wholesome','kindness','spontaneous','outdoors','social'],'quick reflection or check-in','Offer, don''t impose: ask ''can I help?'' first and back off graciously if they decline. Stay in public, well-lit spaces.'),
('crew-cleanup-sprint','Crew Cleanup Sprint','Round up two or three people and do a 20-minute litter sprint of one block, one beach strip, or one park path. Race the timer, fill a bag, leave the spot better than the planet''s been treating it.','Fast, oddly satisfying, and you can literally see your dent in the world. Bonus: it''s the most low-pressure way to hang out and do good at once.','Acts of kindness & wholesome',3,'group',30,0,0,0,'GBP',2,false,ARRAY['wholesome','kindness','outdoors','adventurous','social'],'photo of the full bag and your crew','Wear gloves or use a grabber, never touch sharps or anything hazardous, and skip roadside areas with traffic.'),
('reconnect-with-a-ghost','Reconnect With a Ghost','Pick someone you''ve drifted from for no real reason: an old friend, a relative you keep meaning to call. Reach out today with zero agenda. ''You popped into my head and I just wanted to say hi.'' That''s the whole mission.','Most friendships don''t end in a fight, they end in silence. Breaking that silence is quietly one of the kindest things you can do.','Acts of kindness & wholesome',1,'solo',30,0,0,0,'GBP',1,true,ARRAY['wholesome','kindness','nostalgic','brave','connection'],'reflection on how the reconnect went',NULL),
('the-generous-review','The Generous Review','Think of a tiny local spot you love that''s barely hanging on: a corner cafe, a one-person bookshop, a food cart. Leave them a glowing, specific public review and tell one friend to go. Be their unpaid hype person.','A single warm review can swing a struggling small business. You get to be the reason a stranger''s dream survives another month.','Acts of kindness & wholesome',1,'solo',15,0,0,0,'GBP',1,true,ARRAY['wholesome','kindness','creative','generous','feel-good'],'screenshot of the review you posted',NULL),
('neighbor-favor-drop','Neighbor Favor Drop','Do one unasked-for kindness for a neighbor: bring in their bins, shovel the shared step, leave a ''spare lemons from my tree'' bag on a doorstep. The people closest to you are often the most overlooked.','Real-life community is built from these micro-favors. One small move can turn a hallway stranger into someone who waves hello for years.','Acts of kindness & wholesome',1,'solo',20,0,0,0,'GBP',2,true,ARRAY['wholesome','kindness','cozy','spontaneous','connection'],'photo of the deed done (no faces)','Stick to clearly welcome favors and don''t enter anyone''s private space; if in doubt, knock and offer rather than assume.'),
('sponsor-a-stranger-s-day','Sponsor a Stranger''s Day','Pick one micro-need you can quietly fix in the wild: feed an expiring parking meter, leave a few coins in a vending machine, drop a phone charger at a cafe with a sticky note saying ''borrow me, leave me.'' Solve a problem someone hasn''t even hit yet.','Pre-emptive kindness is sneaky-fun: you''re planting little relief bombs for future-strangers who''ll never see them coming.','Acts of kindness & wholesome',2,'solo',30,1,1,15,'GBP',2,true,ARRAY['wholesome','kindness','creative','spontaneous','generous'],'photo of your little setup','Only leave clearly safe, obviously-shareable items in appropriate public spots, and don''t leave anything that could look alarming or get someone in trouble.'),
('compliment-a-statue','Compliment a Statue','Find a statue, monument, or weirdly proud-looking pigeon. Give it a heartfelt, fully sincere compliment out loud. Bonus points if a stranger overhears and you commit to the bit.','It''s a tiny act of public absurdity that flips your whole nervous system from self-conscious to delighted in about 30 seconds.','Weird, absurd & playful',1,'solo',15,0,0,0,'GBP',1,true,ARRAY['spontaneous','playful','brave','outdoors','lighthearted'],'photo of you and your beautiful new friend (the statue)',NULL),
('the-floor-is-lava-adult-edition','The Floor Is Lava (Adult Edition)','Pick a room. For the next 10 minutes the floor is molten lava. Cross it using only furniture, cushions, and questionable life choices. No, you may not ''just walk normally because you''re a grown-up.''','Reconnects you to the exact kind of pointless joy your eight-year-old self was a world champion at.','Weird, absurd & playful',2,'either',15,0,0,0,'GBP',2,true,ARRAY['playful','nostalgic','cozy','indoors','lighthearted'],'reflection: did you survive, and what''s your final lava-crossing record?','Only climb on furniture that can actually hold you, clear sharp corners, and skip this one if anyone''s prone to a dodgy knee or ankle.'),
('narrate-a-stranger-s-life','Narrate a Stranger''s Life','Sit somewhere public with a friend. Pick a random passerby and quietly invent their entire dramatic backstory together. ''Geoffrey hasn''t told his wife about the alpacas.'' Keep building until one of you cracks.','Turns dead time into a comedy writers'' room and bonds you over a shared inside joke you''ll quote for months.','Weird, absurd & playful',1,'pair',30,0,0,0,'GBP',2,false,ARRAY['playful','social','creative','cozy','lighthearted'],'reflection: write down your favourite invented backstory','Keep it kind and quiet — invent flattering nonsense, never mock anyone, and don''t let them overhear.'),
('order-in-an-accent','Order in an Accent','Walk into a cafe or shop and place your entire order in a completely invented accent. Commit fully. Do NOT break. Tip well, because you are now a mysterious international traveller and they were lovely about it.','Pure low-stakes bravery training disguised as a bit — the kind of dumb dare that''s genuinely thrilling to pull off.','Weird, absurd & playful',2,'solo',15,1,1,15,'GBP',2,true,ARRAY['brave','playful','spontaneous','social','adventurous'],'check-in at the venue + a one-line debrief on whether you cracked','Keep it light and friendly, never mock a real culture or person, and bail gracefully the second it stops being fun for everyone.'),
('adopt-a-plant-name-it-dramatically','Adopt a Plant, Name It Dramatically','Acquire one (1) small plant. Give it a name with no chill whatsoever — Sir Reginald Leafington III, Beyoncé, The Duchess. Introduce it to your home out loud like it''s moving in.','A genuinely warm, slightly unhinged ritual that leaves you with a living roommate and a story every time someone asks ''why is it called that.''','Weird, absurd & playful',1,'solo',30,1,1,15,'GBP',1,true,ARRAY['cozy','playful','creative','nostalgic','indoors'],'photo of the new family member + their full legal name',NULL),
('backwards-walk-block','Backwards Walk Block','Pick a quiet, familiar street and walk one full block facing backwards. Yes, the world looks completely different. Yes, you look completely deranged. Embrace it.','A weirdly meditative reset that makes a route you''ve walked 1,000 times feel brand new — plus a small, ridiculous hit of courage.','Weird, absurd & playful',2,'solo',15,0,0,0,'GBP',2,true,ARRAY['playful','outdoors','spontaneous','adventurous','brave'],'photo of the view behind you that you never normally see','Daylight only, quiet pavement with no traffic or cyclists, and glance over your shoulder often — or ask a friend to spot you so you don''t walk into a bin.'),
('invent-a-holiday-and-celebrate-it','Invent a Holiday and Celebrate It','Right now, declare a brand new holiday. Snail Appreciation Day. National Wear One Sock Inside Out Day. Make up exactly one tradition and DO it within the hour. Wish someone a happy [holiday].','Manufacturing joy out of absolutely nothing is a superpower, and you''ll have a genuinely funny answer to ''how was your day.''','Weird, absurd & playful',1,'either',30,0,0,0,'GBP',1,true,ARRAY['playful','creative','spontaneous','lighthearted','cozy'],'reflection: name the holiday, the tradition, and who you forced to celebrate it',NULL),
('sock-puppet-confession','Sock Puppet Confession','Make a sock puppet (a sock + your hand counts, you don''t need craft supplies). Have it tell you one mildly embarrassing opinion you actually hold. Let the puppet take the heat. The puppet has no shame.','A genuinely freeing, silly bit of play that''s secretly a sneaky way to say a true thing out loud through a very dignified sock.','Weird, absurd & playful',1,'solo',15,0,0,0,'GBP',1,true,ARRAY['playful','creative','cozy','indoors','nostalgic'],'photo of the puppet mid-monologue',NULL),
('the-most-dramatic-possible-exit','The Most Dramatic Possible Exit','Next time you leave a room with friends, leave like it''s the season finale. Pause at the door. Deliver one cryptic line. Vanish. No explanation. Refuse to discuss it later.','Pure chaotic-good energy that turns an ordinary goodbye into a bit your group will be quoting and re-staging for weeks.','Weird, absurd & playful',2,'group',15,0,0,0,'GBP',1,false,ARRAY['playful','social','brave','spontaneous','lighthearted'],'witness — a friend confirms the exit landed (or someone films it)',NULL),
('midnight-kitchen-experiment','Midnight Kitchen Experiment','Tonight, invent one (1) snack that absolutely should not exist. Combine two things no sane person would. Name it. Taste it. Rate it out of ten. The honor system says you must take at least one real bite.','A cozy, low-effort dose of late-night chaos that''s somehow more fun than any normal snack you''d have eaten anyway.','Weird, absurd & playful',1,'either',30,1,1,15,'GBP',2,true,ARRAY['playful','cozy','creative','indoors','spontaneous'],'photo of the abomination + its out-of-ten score','Only combine things you''d normally eat — no expired food, nothing you''re allergic to, and don''t dare a friend with allergies into a taste-test.'),
('speak-only-in-questions','Speak Only in Questions','For one full conversation with a friend, you may ONLY speak in questions. Every single line. ''Did you eat yet?'' ''How could I possibly know that?'' First one to make a statement loses and owes the other a coffee.','An absurd little duel that hijacks a normal chat into something genuinely hilarious — and reveals who among you is dangerously competitive.','Weird, absurd & playful',2,'pair',15,0,0,0,'GBP',1,false,ARRAY['playful','social','lighthearted','brave','spontaneous'],'witness — your opponent confirms who broke first',NULL),
('choreograph-a-10-second-hype-dance','Choreograph a 10-Second Hype Dance','Invent a 10-second dance that plays in your head every time something good happens to you. Practice it once now, fully, no half-effort shuffling. This is your official Victory Sequence from this day forward.','You''re literally installing a physical shortcut to joy that you''ll deploy at the bus stop, in the kitchen, mid-good-news, forever.','Weird, absurd & playful',3,'either',15,0,0,0,'GBP',2,true,ARRAY['playful','high-energy','creative','spontaneous','lighthearted'],'10-second video, or a witness who watched the world premiere','Give yourself clear space to flail — move the coffee table before you launch the Victory Sequence.'),
('leave-a-tiny-anonymous-gift','Leave a Tiny Anonymous Gift','Hide one small, harmless, delightful surprise for a stranger to find — a googly-eyed rock, a kind note, a £1 ''this is your lucky day'' coin taped to a lamppost. Walk away. Never know who finds it.','A quietly magical, slightly mischievous act of chaos-for-good that you''ll think about smiling for the rest of the week.','Weird, absurd & playful',1,'solo',30,1,1,15,'GBP',2,true,ARRAY['playful','outdoors','kind','spontaneous','lighthearted'],'photo of the gift in its hiding spot before you flee the scene','Leave it somewhere public and visible, nothing that could be mistaken for a hazard or block a path, and never on private property or anywhere it''d cause alarm.'),
('teach-in-7','Teach in 7','Pick one thing you actually know how to do and teach it to someone in under 7 minutes. Tying a bowline, the rule of thirds, how mortgages work, your secret garlic technique. If you can teach it, you understand it. If you can''t, you just found the edge of what you know.','Teaching is the fastest way to expose the holes in your own knowledge, and it turns a friend into a witness to something you''re good at.','Skill, learning & growth',1,'pair',20,0,0,0,'GBP',1,false,ARRAY['learning','social','cozy','creative'],'Witness confirms (the person you taught) plus a one-line reflection on what you taught',NULL),
('beginner-brain','Beginner Brain','Go learn something for exactly one hour where you are unmistakably the worst person in the room. A drop-in pottery class, a beginner bouldering session, a community choir. The goal isn''t to be good. It''s to remember what being a total newbie feels like.','Being a beginner on purpose rebuilds the muscle for trying hard things and being okay at sucking. Most adults never feel it again.','Skill, learning & growth',2,'either',60,1,1,15,'GBP',2,true,ARRAY['learning','brave','adventurous','social'],'Photo from the class or a check-in at the venue plus a reflection on the most awkward moment','If it''s physical (climbing, dance, martial arts), warm up and tell the instructor you''re brand new so they can spot you.'),
('ask-the-expert','Ask the Expert','Find someone who''s genuinely brilliant at something you''re curious about and ask them three real questions. The barista who roasts their own beans. Your uncle who fixes engines. The owner of that weird record shop. People love talking about the thing they love. Let them.','Curiosity out loud beats curiosity in your head. You get knowledge you can''t Google and you make someone''s day by being interested.','Skill, learning & growth',1,'solo',30,0,0,0,'GBP',2,true,ARRAY['learning','social','spontaneous','brave'],'Reflection: write down the single best thing they told you','Read the room. If someone''s busy or clearly not up for it, thank them and move on. Don''t corner anyone.'),
('one-phrase-real-world','One Phrase, Real World','Learn to say one genuinely useful sentence in a language you don''t speak. Not ''hello.'' Something with stakes, like ''this is delicious, what''s in it?'' Then actually use it on a real human today. Yes, your accent will be terrible. That''s the fun.','A language only becomes real the first time you use it on a person who answers back. One brave sentence is the whole on-ramp.','Skill, learning & growth',1,'either',30,0,0,0,'GBP',1,true,ARRAY['learning','brave','spontaneous','social'],'Reflection on who you said it to and how they reacted, or a voice note of you saying it',NULL),
('fix-it-yourself','Fix It Yourself','That thing that''s been broken or that you''ve always paid someone else to do? Today you learn it. Watch one good tutorial, then do it. Patch a bike tyre, re-grout a tile, sew a button properly, reset the breaker. Boring competence is a superpower.','Self-reliance compounds. Every small repair you learn is a future panic you''ll never have, and it feels absurdly good to fix your own stuff.','Skill, learning & growth',2,'solo',60,1,1,15,'GBP',2,true,ARRAY['learning','cozy','creative'],'Before-and-after photo of the thing you fixed','Skip anything involving live mains wiring, gas, or structural work unless you genuinely know what you''re doing. When in doubt, watch first, breaker off, and don''t be a hero.'),
('read-it-out-loud','Read It Out Loud','Grab a book you''ve never read, find a quiet spot, and read for 30 minutes straight with your phone in another room. No skimming, no second screen. Just you and the page like it''s 2003. See if your attention span comes back when you let it.','Deep reading is a skill we''re quietly losing. Reclaiming half an hour of real focus is more radical than it sounds, and weirdly restful.','Skill, learning & growth',1,'solo',60,0,0,0,'GBP',1,true,ARRAY['learning','cozy','nostalgic','solo'],'Photo of the page you got to plus your favourite line',NULL),
('skill-swap','Skill Swap','Find a friend and trade lessons. You teach them your thing, they teach you theirs. Thirty minutes each, no money changes hands. Chess for crochet. Excel for guitar chords. Knife skills for parallel parking. Everyone leaves with a new trick.','Mutual teaching makes both of you smarter and gives a friendship something to do besides drinks. It''s the group chat ''we should hang out'' finally cashing out into something you''ll remember.','Skill, learning & growth',2,'pair',60,0,0,0,'GBP',1,false,ARRAY['learning','social','creative','cozy'],'A photo or short clip of both of you mid-lesson, logged to your shared timeline',NULL),
('the-100-word-truth','The 100-Word Truth','Write 100 words about something that actually happened to you this week. Not a journal dump. Tight, honest, shaped. Cut every word that isn''t pulling weight. Writing well is just thinking made visible, and 100 words is enough to start.','Short, deliberate writing sharpens how you think, not just how you sound. It''s the lowest-friction way to build a real creative habit.','Skill, learning & growth',1,'solo',30,0,0,0,'GBP',1,true,ARRAY['learning','creative','cozy','solo'],'Photo of your finished 100 words or paste the text into your reflection',NULL),
('map-without-maps','Map Without Maps','Pick somewhere a 20-minute walk away, look at the route once, then put your phone away and navigate there from memory. Read the street signs. Notice the landmarks. Rebuild the part of your brain that knew where things were before the blue dot did it for you.','Wayfinding is a real, fadeable skill, and doing it manually makes a neighbourhood you ''know'' suddenly vivid again. Bonus: you notice things you''d have walked past staring down.','Skill, learning & growth',2,'solo',60,0,0,0,'GBP',2,true,ARRAY['learning','adventurous','outdoors','spontaneous'],'Check-in at your destination plus a note on one thing you spotted along the way','Keep your phone charged and reachable for emergencies even while it''s pocketed. Stick to areas and times you''d feel comfortable in anyway, and don''t do the no-phone version somewhere unfamiliar after dark.'),
('cook-the-scary-one','Cook the Scary One','Make the dish you''ve always been intimidated by. Fresh pasta. A proper curry from scratch. The thing your gran made that you never learned. One recipe, no shortcuts, the whole production. Worst case you order a pizza and you''ve still learned something.','A hard recipe is a contained, delicious adventure with a built-in reward at the end. You level up a real skill and eat the evidence.','Skill, learning & growth',2,'either',60,1,1,15,'GBP',2,true,ARRAY['learning','creative','cozy','adventurous'],'Photo of the finished plate (and your honest rating of how it turned out)','Standard kitchen sense with hot oil, sharp knives, and raw meat. If you''re cooking for others, check allergies first.'),
('steal-like-a-sketcher','Steal Like a Sketcher','Sit somewhere with a view, get a pen and any scrap of paper, and draw what''s in front of you for 15 minutes. It will look bad. Draw it anyway. You''re not making art, you''re learning to actually look at things, which most people forgot how to do.','Drawing is mostly seeing, and seeing is trainable. Fifteen ugly minutes teaches you to notice detail in a way photos never will.','Skill, learning & growth',1,'solo',30,0,0,0,'GBP',1,true,ARRAY['learning','creative','outdoors','cozy'],'Photo of your sketch, however rough',NULL),
('memorise-something-beautiful','Memorise Something Beautiful','Pick a short poem, a film monologue, or a verse of a song you love and commit it to memory. Properly. So you could recite it cold at a dinner table in 10 years. We outsourced our memories to our phones. Take one small thing back.','Memorising something you love gives you a piece of art you carry everywhere, forever. It''s a quietly impressive party trick and a genuine cognitive workout.','Skill, learning & growth',1,'solo',60,0,0,0,'GBP',1,true,ARRAY['learning','nostalgic','cozy','creative'],'Voice note of you reciting it from memory, no peeking',NULL),
('wrong-hand-day','Wrong-Hand Day','For one hour, do everything with your non-dominant hand. Brush your teeth, eat lunch, write your name, scroll. It''s clumsy and ridiculous and your brain will hate it, which is exactly the point. New wiring only grows when you make things hard.','Forcing the awkward hand is neuroplasticity you can feel in real time. It''s a low-stakes, genuinely funny reminder that your brain is still very much under construction.','Skill, learning & growth',1,'either',60,0,0,0,'GBP',2,true,ARRAY['learning','spontaneous','creative'],'Photo of your wrong-handed signature next to your normal one','Don''t do the wrong-hand thing for anything sharp, hot, or behind the wheel. Keep it to low-risk tasks.'),
('office-hours-reversed','Office Hours, Reversed','Message someone five-plus years ahead of you in something you care about and ask for 20 minutes of their time. A coffee, a call, whatever they''ll give. Come with two specific questions. Most people say yes to genuine curiosity far more than you''d expect.','One honest conversation with someone further down the road can save you years of guessing. The hard part is just asking, and that''s a skill too.','Skill, learning & growth',1,'pair',60,0,0,0,'GBP',2,false,ARRAY['learning','brave','social'],'Reflection on the best piece of advice you walked away with','Meet in a public place or do it as a call if you don''t already know the person well.'),
('single-task-a-cup-of-tea','Single-Task a Cup of Tea','Make a hot drink and then do absolutely nothing else while you drink it. No phone, no screen, no scrolling. Just you, the cup, and the radical act of watching steam. Ten minutes. Pretend your phone fell in a lake.','Single-tasking one small ritual resets a frazzled nervous system faster than any app. It''s the smallest possible dose of presence, and it actually works.','Chill, mindful & solo restoration',1,'solo',15,0,0,0,'GBP',1,true,ARRAY['cozy','mindful','calm','solo','indoors','reset'],'reflection',NULL),
('the-20-minute-nothing','The 20-Minute Nothing','Lie down somewhere comfortable, set a timer for 20 minutes, and do genuinely nothing. Not a nap. Not meditation with rules. Just horizontal and off the clock. Let your brain wander wherever it wants. You have permission to be useless.','Boredom is where your best ideas hide. Doing nothing on purpose is a skill we forgot, and your overstimulated brain will thank you.','Chill, mindful & solo restoration',1,'solo',30,0,0,0,'GBP',1,true,ARRAY['calm','mindful','solo','indoors','reset','rest'],'reflection',NULL),
('sunrise-or-sunset-stakeout','Sunrise (or Sunset) Stakeout','Catch one full sunrise or sunset, start to finish, with your own two eyes. Find a window, a rooftop, a hill, a stoop. Watch the whole color change. No timelapse, no story for later. This one''s just for you.','The sky puts on a free show twice a day and we almost never look. Bookending the day with a slow look at the horizon is quietly profound.','Chill, mindful & solo restoration',1,'solo',40,0,0,0,'GBP',2,true,ARRAY['mindful','outdoors','calm','solo','nostalgic','reset'],'photo','If you''re heading somewhere quiet or elevated for the view, especially around dusk, stick to well-trafficked spots and let someone know where you are.'),
('barefoot-in-the-grass','Barefoot in the Grass','Find some grass, sand, or moss, take your shoes off, and just stand in it for a few minutes. Wiggle your toes. Feel the temperature. It''s ridiculous and it''s lovely and nobody is watching as much as you think they are.','There''s something genuinely grounding about feet on earth, no woo required. Two minutes of texture and cool ground is a tiny nervous-system reboot.','Chill, mindful & solo restoration',1,'solo',15,0,0,0,'GBP',2,true,ARRAY['outdoors','mindful','calm','solo','playful','reset'],'photo','Pick a clean patch you can see clearly, glass and sharp bits hide in grass.'),
('phone-in-the-other-room','Phone in the Other Room','Put your phone in a different room, on purpose, for one full hour. Close the door on it. Read, cook, stretch, stare at the wall, whatever. The point is to feel the itch and then feel it pass. (Yes, log this once you''re back.)','The first ten minutes feel like withdrawal. Then your shoulders drop and time slows down. A phone-free hour is the most restorative thing most of us never do.','Chill, mindful & solo restoration',1,'solo',60,0,0,0,'GBP',1,true,ARRAY['mindful','calm','solo','indoors','reset','rest'],'reflection',NULL),
('slow-bath-real-candle','Slow Bath, Real Candle','Run a proper bath, light an actual candle, and soak with zero agenda. No podcast on 2x speed. Maybe one song on loop. Stay until the water goes lukewarm and you''ve genuinely forgotten what time it is.','Warm water plus dim light is an ancient cheat code for calm. Treating your own rest like it matters is the whole quest.','Chill, mindful & solo restoration',1,'solo',45,1,1,15,'GBP',2,true,ARRAY['cozy','calm','mindful','solo','indoors','rest','selfcare'],'reflection','Keep the candle well away from anything flammable and don''t bring it (or any plugged-in device) near the water.'),
('five-senses-walk','Five Senses Walk','Take a slow, aimless walk and silently name things: 5 you can see, 4 you can hear, 3 you can feel, 2 you can smell, 1 you can taste. No destination, no step goal. Just walk until you feel a little more here than when you left.','It''s a grounding technique disguised as a stroll. By the time you finish the list, your spiraling thoughts have quietly left the building.','Chill, mindful & solo restoration',1,'solo',30,0,0,0,'GBP',2,true,ARRAY['outdoors','mindful','calm','solo','reset','walk'],'check-in','If it''s after dark, stick to lit, familiar routes and keep one ear free for traffic.'),
('cook-one-thing-from-scratch-slowly','Cook One Thing From Scratch, Slowly','Make one simple thing entirely from scratch, no shortcuts, no rushing. Chop like you have all the time in the world. Soup, bread, a sauce, whatever. The meal is a bonus. The slow, hands-busy quiet is the actual point.','Repetitive handwork (chopping, stirring, kneading) is moving meditation that ends in dinner. Few things calm a noisy head like a knife and an onion.','Chill, mindful & solo restoration',2,'solo',60,1,1,15,'GBP',1,true,ARRAY['cozy','creative','mindful','calm','solo','indoors','selfcare'],'photo',NULL),
('write-a-letter-you-ll-never-send','Write a Letter You''ll Never Send','Grab paper and a pen (real ones) and write a letter to someone, past or present, that you have no intention of sending. Say the unsaid thing. Then fold it up and keep it or rip it up. Either is correct.','Getting the loop closed on paper does something a Notes app can''t. It''s the cheapest, most private form of catharsis there is.','Chill, mindful & solo restoration',1,'solo',30,0,0,0,'GBP',1,true,ARRAY['mindful','creative','nostalgic','calm','solo','indoors','reflective'],'reflection',NULL),
('cloud-watching-like-a-kid','Cloud Watching, Like a Kid','Lie back somewhere outside and watch the clouds for a while. Find shapes. Pick a favorite. Let one drift fully across your view before you get up. If there are no clouds, congratulations, just stare at the blue.','It''s free, it''s ancient, and it forces your eyes to relax and your brain to slow to cloud-speed. Pure nostalgic, no-stakes restoration.','Chill, mindful & solo restoration',1,'solo',20,0,0,0,'GBP',1,true,ARRAY['outdoors','nostalgic','calm','mindful','solo','playful','reset'],'photo',NULL),
('the-one-object-declutter','The One-Object Declutter','Pick ONE small surface, a shelf, a drawer, your nightstand, and reset only that. Don''t spiral into deep-cleaning the whole house. One spot, made calm. Then sit nearby and admire your single corner of order.','Tidying a tiny defined space gives you a real hit of control and a visibly calmer corner, without the all-day cleaning trap. Small, finished, soothing.','Chill, mindful & solo restoration',2,'solo',30,0,0,0,'GBP',1,true,ARRAY['calm','mindful','solo','indoors','reset','selfcare','cozy'],'photo',NULL),
('stargaze-phone-dark','Stargaze, Phone Dark','Get somewhere you can see the night sky, lie back, and just look up for a while. Phone in your pocket, screen off, eyes adjusting. See how many stars show up after five minutes of patience. Bonus points if you can find one constellation.','Letting your eyes adapt to the dark and feeling genuinely small under the sky is one of the oldest forms of awe. It quietly rightsizes everything you were stressing about.','Chill, mindful & solo restoration',1,'solo',40,0,0,0,'GBP',2,true,ARRAY['outdoors','mindful','calm','solo','nostalgic','awe','night'],'photo','Going somewhere dark at night: pick a safe, familiar spot, tell someone where you are, and consider bringing a friend if it''s remote or unlit.'),
('slow-coffee-shop-solo-date','Slow Coffee-Shop Solo Date','Take yourself out, alone, to a cafe. Order the nice thing. Bring a book or a notebook, not your laptop, and sit for a proper while. No meeting, no working, no waiting for anyone. Just your own good company.','Learning to enjoy your own company in public is a quietly powerful skill. A solo date reframes ''alone'' as ''chosen,'' and that shift is genuinely restorative.','Chill, mindful & solo restoration',1,'solo',60,1,1,15,'GBP',1,true,ARRAY['cozy','calm','mindful','solo','selfcare','reflective','indoors'],'photo',NULL),
('stretch-it-out-in-the-dark','Stretch It Out in the Dark','Tonight, before bed, kill the overhead lights, put on one slow song, and do five lazy stretches. No routine to follow, no app counting reps. Just reach, breathe, and unkink whatever today knotted up. Then go straight to bed.','A tiny wind-down ritual signals your body that the day is genuinely over, and it sleeps better for it. Low effort, surprisingly high reward.','Chill, mindful & solo restoration',1,'solo',15,0,0,0,'GBP',2,true,ARRAY['calm','mindful','solo','indoors','rest','selfcare','night'],'reflection','Ease into stretches gently, don''t force anything that hurts.'),
('resurrect-the-dead-plan','Resurrect the Dead Plan','You know that hangout your group chat has ''definitely'' been doing for 4 months? Pick the most-flaked-on plan, name a date, and dare two friends to lock it in right now. No vibe-check. No ''maybe.'' A time and a place.','The whole point: the thing that dies in the group chat becomes a real thing on a real calendar. One tap kills the curse.','Group / party / co-op with the network',1,'group',15,0,0,0,'GBP',1,false,ARRAY['social','spontaneous','accountable','connection','low-key'],'check-in: everyone confirms the locked date in the quest thread',NULL),
('two-friend-cook-off','Two-Friend Cook-Off','Dare a friend to a kitchen duel. Same secret ingredient, separate kitchens, one hour on the clock. Trade photos of the chaos and the plating. A neutral third friend crowns a winner. Loser owes dinner.','Cooking alone is a chore. Cooking competitively against a friend you''ll roast forever is content. The ''loser owes dinner'' creates the next quest automatically.','Group / party / co-op with the network',2,'group',60,1,1,15,'GBP',2,false,ARRAY['creative','social','competitive','cozy','homemade','duo'],'photo: each cook posts their final dish; judge logs the verdict','Usual kitchen sense — hot pans, sharp knives, don''t leave the stove unattended for the photo.'),
('mystery-picnic','Mystery Picnic','Split a picnic blind. Each person brings one item nobody else knows about — drink, snack, the weird thing, the dessert nobody asked for. Meet at a park, lay it all out, and find out if you''ve assembled a feast or four bags of crisps and a single grape.','The reveal is the joy. Low stakes, high delight, and somehow always ends in one perfect accidental combo.','Group / party / co-op with the network',1,'group',60,1,1,15,'GBP',2,false,ARRAY['outdoors','cozy','spontaneous','social','playful','food'],'photo: the full spread laid out together','If anyone in the group has allergies, share ingredient lists before you dig in.'),
('tourist-in-your-own-town','Tourist In Your Own Town','Grab your crew and do the one famous local thing you''ve all lived near for years and never done. The viewpoint, the old museum, the bridge in every postcard. Be unironic tourists for an afternoon. Take the embarrassing photo on purpose.','Everyone has a hometown landmark they''ve smugly ignored. Doing it together turns ''we should'' into a genuinely good day and a stupid group photo.','Group / party / co-op with the network',2,'group',60,1,1,15,'GBP',1,false,ARRAY['adventurous','outdoors','social','nostalgic','exploring','daytime'],'photo: the deliberately touristy group shot at the spot',NULL),
('the-8pm-walk-and-talk','The 8pm Walk-and-Talk','Text one friend: ''walk in 20?'' Then actually do it. No destination, no agenda, just a loop around the block while the day winds down. The best conversations happen when nobody''s looking at each other.','The lowest-friction way to see a friend on a weeknight. No booking, no money, no plan — just the thing humans are best at, walking and talking.','Group / party / co-op with the network',1,'pair',45,0,0,0,'GBP',2,false,ARRAY['cozy','low-key','connection','outdoors','spontaneous','duo','evening'],'check-in: both tap done when you part ways','Stick to lit, familiar routes after dark, and tell someone else your loop if you''re going somewhere quiet.'),
('game-night-phones-in-the-bowl','Game Night, Phones In The Bowl','Host the game night your group keeps threatening to have. One rule: every phone goes in a bowl by the door on arrival. First to crack and reach for it does the washing up. Cards, dice, that dusty board game — your call.','Game nights die in the planning. This one has a host, a date, and a rule that makes the room actually present. The phone-bowl is the whole gimmick and it works.','Group / party / co-op with the network',2,'group',60,0,0,0,'GBP',2,false,ARRAY['social','cozy','playful','competitive','homemade','evening'],'photo: the bowl of confiscated phones','Keep one phone reachable for genuine emergencies — agree which before it goes in the bowl.'),
('dawn-patrol','Dawn Patrol','Talk one brave friend into watching the sunrise with you. Set the alarm, meet somewhere with a view, bring a flask of something hot. Watch the sky do the thing while the rest of the city sleeps. Then go get breakfast like absolute legends.','Sunrises are wasted alone — you need a witness. Doing something slightly unreasonable with one other person is the fastest way to a story you''ll both retell for years.','Group / party / co-op with the network',3,'pair',60,1,1,15,'GBP',2,false,ARRAY['adventurous','outdoors','brave','connection','nostalgic','duo'],'photo: the two of you against the sunrise','Plan your route in daylight first, travel together rather than meeting at a remote spot in the dark, and keep your phone charged.'),
('the-reverse-surprise-party','The Reverse Surprise Party','Don''t wait for a birthday. Gather 3+ people and surprise one friend who''s had a rough stretch — just because. Coordinate in secret, show up at their door (or summon them to a cafe), and make the occasion be them. No reason needed beyond ''we like you.''','Surprise parties are hoarded for milestones. Spending one on someone for no reason at all is one of the most quietly powerful things a friend group can do.','Group / party / co-op with the network',2,'group',60,1,1,15,'GBP',2,false,ARRAY['social','connection','kind','spontaneous','celebration','group'],'witness: the surprised friend confirms in the thread; group photo optional','Make sure the person actually likes surprises and isn''t going through something where a sudden crowd would overwhelm them — when in doubt, a gentle heads-up beats a true ambush.'),
('skill-swap-hour','Skill Swap Hour','Pair up with a friend who''s good at a thing you''re not. One hour, you teach them yours, they teach you theirs. Guitar for baking. Skateboarding for spreadsheets. Doesn''t matter if either of you is any good by the end — that''s not the point.','Turns ''we should hang out'' into ''we made each other slightly more interesting.'' Teaching a friend your weird skill is a genuine intimacy hack.','Group / party / co-op with the network',2,'pair',60,0,0,0,'GBP',1,false,ARRAY['creative','connection','social','learning','duo','low-key'],'reflection: each person notes the one thing they learned',NULL),
('last-minute-yes-day','Last-Minute Yes Day','Message your most spontaneous friend right now with: ''I''m free in an hour. What are we doing?'' Then say yes to whatever they suggest, within reason. Hand over the steering wheel for one afternoon and see where you end up.','The whole magic of the app in one quest — pure spontaneity, zero planning, total trust. The best afternoons are the unplanned ones you almost talked yourself out of.','Group / party / co-op with the network',3,'pair',60,1,1,15,'GBP',2,false,ARRAY['spontaneous','adventurous','social','brave','exploring','duo'],'photo: wherever you unexpectedly ended up','''Within reason'' is the rule — you can always veto anything that costs too much, feels unsafe, or crosses a line. Saying yes isn''t saying yes to everything.'),
('crew-karaoke-ambush','Crew Karaoke Ambush','Rally the group and go fully send it at karaoke. Everyone has to sing at least once — no exceptions, no hiding behind the tambourine. Assign someone the worst possible song for someone else. Solidarity through mutual embarrassment.','Nobody regrets a karaoke night. The forced-participation rule means nobody gets to be the person who ''just watches'' — which is exactly the person who needed it most.','Group / party / co-op with the network',3,'group',60,2,20,60,'GBP',2,false,ARRAY['social','playful','brave','celebration','high-energy','group','evening'],'photo or short clip: someone mid-song','If it''s a late night out with drinks, sort your way home in advance and look out for each other on the way back.'),
('three-stop-wander','Three-Stop Wander','Meet a friend with no plan and a simple rule: three stops, none of you choose your own. You pick stop one for them, they pick stop two for you, and a coin (or a stranger''s recommendation) picks the third. Cafe, shop, view, bench — anywhere.','Removes the ''where do you want to go?'' / ''I don''t mind, you?'' death spiral that ends half of all hangouts before they start. The constraint makes the afternoon.','Group / party / co-op with the network',2,'pair',60,1,1,15,'GBP',1,false,ARRAY['exploring','spontaneous','social','adventurous','outdoors','duo'],'photo: one shot from each of the three stops',NULL),
('the-standing-order','The Standing Order','Pick one friend and one repeating slot — first Sunday coffee, Wednesday phone call, last-Friday pint. Set it once, commit to it together, and make it the thing that doesn''t need re-planning every time. Recurring beats spontaneous when life gets busy.','The strongest friendships have a ritual. This turns a single hangout into an automatic one, which is the real long game of staying close to people.','Group / party / co-op with the network',1,'pair',45,1,1,15,'GBP',1,false,ARRAY['connection','cozy','low-key','accountable','ritual','duo'],'check-in: both confirm the recurring slot; logged each time it happens',NULL),
('potluck-of-embarrassing-talents','Potluck Of Embarrassing Talents','Throw a tiny showcase night where the price of entry is one hidden talent or deeply pointless skill. Can you whistle two notes at once? Recite a film word-for-word? Fold a fitted sheet? Bring it. Everyone performs, everyone applauds, nobody judges.','Reveals the gloriously weird sides of people you thought you knew. Cheap, warm, and the kind of night that becomes a running group reference forever.','Group / party / co-op with the network',2,'group',60,1,1,15,'GBP',1,false,ARRAY['playful','social','creative','cozy','celebration','group','homemade'],'reflection or short clip: each person logs the talent they brought',NULL),
('blind-taste-roulette','Blind Taste Roulette','Grab a friend, raid the fridge or a corner shop, and feed each other three mystery bites with eyes closed. Guess what it is before you swallow. Loser buys the next snack.','Turns your own kitchen into a game show. You learn how little you actually trust your tongue, and it''s genuinely hilarious.','Food, taste & sensory',1,'pair',30,1,1,15,'GBP',2,false,ARRAY['playful','social','cozy','spontaneous'],'photo of the blindfold or the mystery snack lineup','Skip anything either of you is allergic to. No surprise ingredients without checking allergies first.'),
('the-cheapest-treat-crawl','The Cheapest Treat Crawl','You have a fiver. Spend it on the three smallest, weirdest, most tempting things you can find on one shop''s shelves. Rank them best to worst when you get home.','A tiny budget forces real choices and makes a boring shop run feel like a treasure hunt. Pure low-effort dopamine.','Food, taste & sensory',1,'solo',30,1,1,15,'GBP',1,true,ARRAY['spontaneous','playful','curious','low-key'],'photo of your haul ranked left to right',NULL),
('order-the-thing-you-can-t-pronounce','Order The Thing You Can''t Pronounce','Next time you''re getting food out, order the one item on the menu you have no idea about. No googling, no asking. Whatever lands, you eat it and report back.','Most of us order the same five things forever. This is the cheapest way to find a new favourite or a great story.','Food, taste & sensory',1,'either',60,1,1,15,'GBP',2,true,ARRAY['brave','curious','adventurous','spontaneous'],'photo of the dish + a one-line verdict','Glance at allergens before you commit if you have any.'),
('one-ingredient-total-improv','One Ingredient, Total Improv','Pick one ingredient you''ve never cooked with. Build a whole meal around it tonight with zero recipe. Trust your gut, plate it like you mean it, taste as you go.','Cooking without a net is where you actually get good. Even a flop teaches you something the recipe never would.','Food, taste & sensory',2,'solo',60,1,1,15,'GBP',2,true,ARRAY['creative','adventurous','cozy','curious'],'photo of the finished plate','Standard kitchen sense: hot pans, sharp knives, and cook proteins through.'),
('spice-tier-challenge','Spice Tier Challenge','Order or make the same dish at a spice level one step braver than your usual. Sit with the burn. Milk, bread, and bragging rights on standby.','A controlled little adrenaline hit you can do over dinner. Shared suffering bonds people fast.','Food, taste & sensory',2,'pair',60,1,1,15,'GBP',2,false,ARRAY['brave','playful','social','adventurous'],'photo or a quick selfie mid-suffering','Know your gut. Anyone with reflux, ulcers, or chilli sensitivity should sit this one out. Keep dairy nearby, never escalate past comfort.'),
('recreate-a-childhood-snack','Recreate A Childhood Snack','Track down or make that one snack that tastes like being nine years old. The exact crisp, the corner-shop sweet, the after-school sandwich. Eat it slowly and let the memory hit.','Taste is the most direct line to memory we have. This one is quietly emotional in the best way.','Food, taste & sensory',1,'solo',30,1,1,15,'GBP',1,true,ARRAY['nostalgic','cozy','low-key','reflective'],'photo + a sentence on the memory it brought back',NULL),
('five-senses-one-cup','Five Senses, One Cup','Make a hot drink and actually pay attention. Smell it before you sip. Notice the warmth, the colour, the first taste vs the last. Two slow minutes, no phone.','You drink this every day on autopilot. Tasting it on purpose is a tiny reset that costs nothing and lands every time.','Food, taste & sensory',1,'solo',15,0,0,0,'GBP',1,true,ARRAY['cozy','mindful','low-key','reflective'],'reflection: note one thing you''d never noticed before',NULL),
('cook-a-stranger-s-country','Cook A Stranger''s Country','Pick a country you''ve never cooked food from, find one classic home dish, and make it from scratch tonight. Bonus points for the right music while you stir.','An evening of travelling without leaving the kitchen. Way better shared, and the leftovers are a gift to future-you.','Food, taste & sensory',3,'group',60,2,20,60,'GBP',2,false,ARRAY['adventurous','creative','social','curious'],'photo of the spread on the table','Usual kitchen caution and check guests'' allergies before they arrive.'),
('dessert-before-you-ve-earned-it','Dessert Before You''ve Earned It','Today, dessert comes first. Find the most ridiculous sweet thing within reach and have it before any ''real'' food. No guilt allowed for the next hour.','Breaking a dumb little rule on purpose is weirdly freeing. Two minutes of harmless rebellion.','Food, taste & sensory',1,'either',15,1,1,15,'GBP',1,true,ARRAY['playful','spontaneous','indulgent','joyful'],'photo of the dessert (and the smug face)',NULL),
('the-farmers-market-wildcard','The Farmers Market Wildcard','Hit a market or greengrocer and buy one fruit or veg you can''t name. Ask the seller how they''d eat it. Take it home and do exactly that.','Real people who sell food know things Google doesn''t. You get a new ingredient and a small human exchange in one go.','Food, taste & sensory',2,'solo',60,1,1,15,'GBP',2,true,ARRAY['curious','outdoors','adventurous','spontaneous'],'photo of the mystery produce before and after','If you''re foraging anything wild rather than buying, don''t eat it unless you''re 100 percent certain it''s safe.'),
('build-the-perfect-bite','Build The Perfect Bite','Engineer the single greatest mouthful you can from whatever''s in your kitchen. Layer it, balance it, sweet-salty-crunchy-soft. One bite, no compromises.','Pure edible creativity with zero shopping. Surprisingly competitive when two of you are building rival bites.','Food, taste & sensory',1,'pair',30,0,0,0,'GBP',1,false,ARRAY['creative','playful','cozy','low-key'],'photo of the bite, then have someone judge it',NULL),
('midnight-diner-run','Midnight Diner Run','Late tonight, go out for the kind of food that only tastes right after dark. The 24-hour kebab, the diner stack, the bag of chips on a wall. Savour the weird magic of eating at an hour you shouldn''t.','Food after midnight just hits different. It''s the kind of small adventure that becomes a story you retell for years.','Food, taste & sensory',2,'group',60,1,1,15,'GBP',2,false,ARRAY['spontaneous','adventurous','social','playful'],'photo of the late-night feast','It''s late, so go with at least one other person, stick to well-lit places, and keep an eye on how you''re getting home.'),
('texture-only-tasting','Texture-Only Tasting','Pick three foods purely for how they feel in your mouth, ignore flavour entirely. Crunchy, creamy, springy. Eat them back to back and notice what your tongue is actually doing.','We obsess over flavour and ignore texture, which is half of why we love food. A tiny, free perception experiment.','Food, taste & sensory',1,'solo',15,0,0,0,'GBP',1,true,ARRAY['mindful','curious','low-key','playful'],'reflection: rank them by feel, not taste',NULL),
('cook-for-someone-no-reason','Cook For Someone, No Reason','Make a proper plate of food for one person who isn''t expecting it. A flatmate, a neighbour, a friend mid-bad-week. Hand it over with zero occasion attached.','Feeding someone for no reason is one of the warmest things you can do. The cooking is the gift, the surprise is the magic.','Food, taste & sensory',2,'pair',60,1,1,15,'GBP',2,false,ARRAY['social','cozy','kind','creative'],'witness: the person you fed, plus a photo of the plate','Check what they can and can''t eat before you cook.'),
('the-11pm-voice-note','The 11pm Voice Note','Skip the text. Send the person you''re into a voice note right now — 20 seconds, no script, just say the thing you''d normally overthink. Hearing your actual voice hits different.','Voice is intimacy on hard mode — it carries warmth, nerves, and you, all at once. It''s the difference between ''hey'' and being remembered.','Romance, dates & flirtation',1,'solo',10,0,0,0,'GBP',1,true,ARRAY['spontaneous','brave','cozy','romance'],'reflection: log how you felt before vs. after hitting send',NULL),
('compliment-a-stranger-mean-it','Compliment a Stranger, Mean It','Out in the world today, give one genuine compliment to a stranger — their jacket, their dog, the book they''re reading. No follow-up agenda. Just leave a tiny dent of warmth and walk on.','Flirtation muscles are just courage muscles. This is the lightest rep there is, and it makes the whole day feel more alive — for both of you.','Romance, dates & flirtation',1,'solo',15,0,0,0,'GBP',2,true,ARRAY['brave','social','spontaneous','kindness'],'check-in: tap done and note what you said','Keep it about something they chose (clothes, pet, book), not their body. Read the room — if they''re not into it, smile and move on. No following or persisting.'),
('first-date-reroll','First-Date Reroll','You and your person: ditch the dinner script. Go somewhere neither of you has been — a weird museum, a night market, a tiny gig — and treat it like a first date even if it''s your 50th.','Novelty literally rekindles attraction (your brain reads new experiences as exciting and pins that feeling on each other). Cheaper than a relationship reset.','Romance, dates & flirtation',2,'pair',90,1,1,15,'GBP',1,false,ARRAY['adventurous','romance','spontaneous','outdoors'],'photo: one shot from the place you''ve never been',NULL),
('the-36-questions-speedrun','The 36 Questions, Speedrun','Pick someone — a date, a crush, a long-term love — and trade five of the famous closeness questions over one drink. Start light, end with: ''When did you last cry, and why?''','These questions are the ones psychologists used to make strangers fall in love in a lab. Five is plenty to skip three months of small talk.','Romance, dates & flirtation',1,'pair',60,1,1,15,'GBP',1,false,ARRAY['cozy','romance','brave','creative'],'reflection: note the one answer that surprised you',NULL),
('slide-into-the-group-chat-s-dms','Slide Into the Group Chat''s DMs','There''s someone your friends keep saying you''d ''totally vibe with.'' Stop letting it die in the chat. Ask a mutual to make the intro today — or just message the person yourself.','The best matches rot in everyone''s good intentions. One nudge turns ''we should set them up'' into an actual story.','Romance, dates & flirtation',1,'group',20,0,0,0,'GBP',2,false,ARRAY['social','brave','spontaneous','romance'],'check-in: log who you asked or messaged','Only set people up who''ve actually expressed openness — no surprise-ambushing anyone into a date they didn''t sign up for.'),
('cook-the-thing-they-mentioned-once','Cook the Thing They Mentioned Once','Your person offhandedly loved some dish — a grandma''s recipe, a thing from a trip, a childhood snack. Hunt down how to make it and surprise them with it this week.','Remembering the small thing they said in passing is the entire game. This is ''I was listening'' you can taste.','Romance, dates & flirtation',2,'pair',60,1,1,15,'GBP',1,false,ARRAY['cozy','nostalgic','romance','creative'],'photo: the dish (slightly burnt counts)',NULL),
('golden-hour-phones-down','Golden Hour, Phones Down','Grab your person and go watch the sun go down somewhere — rooftop, hill, harbour wall. The only rule: phones stay in pockets the whole time. Just talk.','Nothing flirty about a screen. Pretty light, a deadline (the sun), and undivided attention is a date format that''s never once failed.','Romance, dates & flirtation',1,'pair',60,0,0,0,'GBP',2,false,ARRAY['cozy','outdoors','romance','spontaneous'],'photo: the sky, taken AFTER it''s set so you actually watched it','If you''re heading somewhere remote or unlit, share your location with a friend and stick to spots you know.'),
('the-bold-ask','The Bold Ask','You know the person you''ve been orbiting for weeks. Today''s the day: ask them out, plainly, with an actual plan and time. ''Drinks Thursday at 7?'' beats ''we should hang sometime'' every single time.','Maybes are where romance goes to die. A specific invite is brave, kind, and almost impossible to misread. Worst case: clarity. Best case: everything.','Romance, dates & flirtation',2,'pair',15,0,0,0,'GBP',2,false,ARRAY['brave','romance','spontaneous'],'reflection: log the ask and how it landed — yes, no, or maybe, you did the brave thing','Ask once, clearly. If it''s a no or a non-answer, take it graciously and back off — persistence isn''t romance.'),
('speed-date-your-own-city','Speed-Date Your Own City','Going solo? Hit a singles mixer, a board-game café night, a run club, or a hobby class where talking to people is the whole point. Set one goal: have three real conversations.','You meet way more interesting people doing a thing than waiting on an app. Lower stakes, better lighting, actual humans.','Romance, dates & flirtation',3,'either',60,1,1,15,'GBP',2,true,ARRAY['social','brave','adventurous','spontaneous'],'check-in: tap done for each of your three conversations','Choose public, organized events. Tell a friend where you''ll be, arrange your own transport home, and trust your gut if anyone makes you uneasy.'),
('handwrite-it','Handwrite It','Write your person an actual paper note — three lines, real pen — about one specific thing you love that they do. Leave it where they''ll find it. No emoji, no autocorrect, no take-backs.','Handwriting is so rare now it lands like a small grenade of sincerity. They''ll keep it in a drawer for years.','Romance, dates & flirtation',1,'solo',20,0,0,0,'GBP',1,true,ARRAY['cozy','nostalgic','romance','creative'],'photo: the note before you hide it',NULL),
('recreate-the-first-time','Recreate the First Time','Go back to where it started — the bar, the bench, the bus stop, the corner of that party. Stand exactly there with your person and retell each other your version of that night.','Two people almost never remember the beginning the same way, and comparing notes is unbearably sweet. Memory lane, but make it a date.','Romance, dates & flirtation',1,'pair',60,0,0,0,'GBP',1,false,ARRAY['nostalgic','romance','cozy'],'photo: a then-and-now at the original spot',NULL),
('dance-in-the-kitchen','Dance in the Kitchen','Tonight, no audience, no occasion: queue one song, grab your person, and slow-dance in the kitchen with the bad lighting and the dishes still in the sink. Three minutes of nothing-but-this.','The most romantic moments are never the planned big ones. They''re the ridiculous small ones you choose to make. This is free and it works.','Romance, dates & flirtation',1,'pair',10,0,0,0,'GBP',1,false,ARRAY['cozy','spontaneous','romance','nostalgic'],'reflection: name the song you picked',NULL),
('the-surprise-mid-day-pickup','The Surprise Mid-Day Pickup','Show up unannounced where your person is — outside their work, their class, their gym — with a coffee and ten free minutes. No reason, no occasion. Just ''I wanted to see your face.''','Effort with zero prompt is the loudest love language. A planned date is nice. Being someone''s unexpected good thing on a Tuesday is unforgettable.','Romance, dates & flirtation',2,'pair',40,1,1,15,'GBP',2,false,ARRAY['spontaneous','romance','brave'],'photo: the two coffees in hand','Only surprise someone who''ll welcome it — a partner or close date, not a new crush or someone who hasn''t shared where they''ll be. A surprise should never feel like being tracked.'),
('flirt-by-letter-old-school','Flirt by Letter, Old-School','Pick someone you''re into and trade voice-or-text answers to one playful question a day for a week: best worst date, three things you''d never admit on a first meeting, the song that''s secretly about them. Slow burn on purpose.','Anticipation is the most underrated part of attraction. Stretching the getting-to-know-you into a daily ritual makes the whole week hum.','Romance, dates & flirtation',1,'pair',15,0,0,0,'GBP',2,false,ARRAY['creative','romance','cozy','spontaneous'],'check-in: tap done each day you send your question','Keep the playfulness mutual — if their answers go short or slow, ease off rather than pushing.'),
('chase-the-last-light','Chase the Last Light','Golden hour is sneaking up. Drop whatever you''re doing 20 minutes before sunset, get yourself somewhere with a clear view of the sky, and just watch it go. No errands attached. The sunset is the whole point.','The best free show in your city happens every single evening and you keep missing it. This is permission to stop and actually catch it.','Seasonal, nocturnal & golden-hour',1,'either',30,0,0,0,'GBP',1,true,ARRAY['cozy','spontaneous','outdoors','golden-hour','solo-friendly'],'photo of the sky at the moment the light goes',NULL),
('golden-hour-portrait-swap','Golden Hour Portrait Swap','Grab a friend and head out during the golden hour. Take turns being each other''s photographer for 15 minutes. Rule: every shot has to use that warm light somehow. Trade your three favourites of each other afterward.','Everyone looks unfairly good in golden hour, and you end up with photos of your friend that they''ll actually keep. Low effort, weirdly meaningful.','Seasonal, nocturnal & golden-hour',2,'pair',45,0,0,0,'GBP',1,false,ARRAY['creative','social','golden-hour','outdoors','playful'],'photo — your favourite shot of your friend',NULL),
('night-walk-no-destination','Night Walk, No Destination','After dark, go for a 30-minute walk through your neighbourhood with absolutely no destination. Take turns picking which way to turn at every corner. Notice how different the same streets feel at night.','Your own area becomes a slightly different planet after dark. Wandering it with no goal is unreasonably calming.','Seasonal, nocturnal & golden-hour',1,'either',45,0,0,0,'GBP',2,true,ARRAY['nocturnal','cozy','outdoors','spontaneous','social'],'check-in at your farthest point from home','Stick to well-lit, familiar streets and tell someone your rough route. If walking solo, keep to busier areas and trust your gut.'),
('stargaze-like-you-mean-it','Stargaze Like You Mean It','Find the darkest spot you can safely reach tonight, lie down, and look up for a full 10 minutes — no phone. Bonus: pull up a free star-map app for ONE minute first to find one constellation, then put it away.','We almost never look up. Ten honest minutes under the sky resets something in your brain that scrolling never will.','Seasonal, nocturnal & golden-hour',1,'either',30,0,0,0,'GBP',2,true,ARRAY['nocturnal','cozy','outdoors','reflective','nostalgic'],'reflection — what''s one thing you noticed up there?','Pick somewhere you''d feel comfortable in daylight; go with someone if you''re heading anywhere remote, and let a friend know where you are.'),
('first-frost-first-bloom-hunt','First Frost / First Bloom Hunt','Whatever season just changed, go find the proof of it. First frost on a windscreen, first blossom on a branch, first fallen leaf worth keeping, first warm day in a t-shirt. Bring home one tiny piece of evidence.','Seasons turn whether you notice or not. Catching the exact moment one tips into the next makes the year feel less like it''s slipping past you.','Seasonal, nocturnal & golden-hour',1,'either',30,0,0,0,'GBP',1,true,ARRAY['seasonal','outdoors','nostalgic','reflective','spontaneous'],'photo of your seasonal evidence',NULL),
('sunrise-mission-2','Sunrise Mission','Set the alarm. Get up before dawn, get somewhere with a view, and watch the sun actually rise. Bring a thermos. Say nothing for the first five minutes — just watch the world switch on.','Almost nobody does this on purpose, which is exactly why it feels like you''ve cheated the day. You''ll talk about this one for weeks.','Seasonal, nocturnal & golden-hour',2,'either',60,1,1,15,'GBP',2,true,ARRAY['golden-hour','adventurous','brave','outdoors','social'],'photo of the sunrise from your spot','Travelling pre-dawn? Go with someone or share your location, choose a route you know, and watch your footing in the dark.'),
('seasonal-dish-you-ve-never-cooked','Seasonal Dish You''ve Never Cooked','Cook one thing that only makes sense this time of year — mulled something, the first BBQ, a stew, summer''s first cold noodle bowl. Use one ingredient that''s actually in season right now. Feed at least one other person.','Eating with the season is the oldest comfort there is, and ''I made the first stew of autumn'' hits different than ''I reheated something''.','Seasonal, nocturnal & golden-hour',2,'group',60,1,1,15,'GBP',1,false,ARRAY['seasonal','cozy','creative','social','homebody'],'photo of the finished dish on the table',NULL),
('blue-hour-photo-five','Blue Hour Photo Five','Blue hour is that short, electric window just after sunset when the sky goes deep blue and the streetlights kick on. You''ve got maybe 20 minutes. Capture five photos before it ends. Best one wins your wallpaper slot for the week.','It''s the most cinematic light of the day and it''s gone in minutes — a tiny urgent treasure hunt with a beautiful payoff.','Seasonal, nocturnal & golden-hour',2,'either',30,0,0,0,'GBP',2,true,ARRAY['golden-hour','creative','outdoors','spontaneous','playful'],'photo — your five-shot pick','Stay aware of traffic and your surroundings while you''re framing shots in low light.'),
('midnight-snack-pilgrimage','Midnight Snack Pilgrimage','Pick a late-night food spot you''ve never tried — a 24-hour diner, a kebab place, a corner that does noodles til 2am — and make the trip after 10pm. Order the thing the staff recommend, not the thing you''d usually get.','Cities have a whole secret nocturnal personality, and late-night food places are where it lives. Going on purpose feels like joining a club you didn''t know existed.','Seasonal, nocturnal & golden-hour',2,'either',60,1,1,15,'GBP',2,true,ARRAY['nocturnal','adventurous','social','spontaneous','foodie'],'photo of the spot or the meal','Plan how you''re getting home before you go, ideally travel with someone, and stick to areas that feel busy and well-lit at night.'),
('catch-the-full-moon','Catch the Full Moon','Check when the moon rises tonight (one quick search). Be outside to watch it come up over the horizon — it''s enormous and orange right as it clears the skyline. If it''s a clear night, this is free magic.','A rising full moon over rooftops is genuinely jaw-dropping and most people have never deliberately watched one. Timed right, it feels like a secret.','Seasonal, nocturnal & golden-hour',1,'either',30,0,0,0,'GBP',2,true,ARRAY['nocturnal','outdoors','cozy','reflective','spontaneous'],'photo of the moon clearing the horizon','Choose a viewing spot you''re comfortable in after dark; bring a friend if you''re heading anywhere quiet.'),
('seasonal-bucket-list-one-liner','Seasonal Bucket-List One-Liner','Name the ONE thing you say every year you''ll do this season and never do — the cold swim, the first snow walk, the autumn forest trip, the festival you keep missing. Text a friend right now and lock in a date for it.','Every season has that one ''we always mean to'' thing. This is the nudge that turns the dormant group-chat plan into an actual diary entry.','Seasonal, nocturnal & golden-hour',1,'pair',30,0,0,0,'GBP',1,false,ARRAY['seasonal','social','spontaneous','adventurous','reflective'],'witness — screenshot of the message where you locked the date',NULL),
('golden-hour-picnic-ambush','Golden Hour Picnic Ambush','Pack the laziest possible picnic — snacks from the corner shop count — and get to a park, rooftop, or hillside one hour before sunset with a friend or two. Stay until the light''s fully gone. No agenda but the view and good company.','The golden-hour-into-dusk picnic is the platonic ideal of a good evening, and it costs almost nothing. You leave feeling like you got away with something.','Seasonal, nocturnal & golden-hour',2,'group',60,1,1,15,'GBP',2,false,ARRAY['golden-hour','social','cozy','outdoors','spontaneous'],'photo of the spread (or the view) at golden hour','Know when your spot closes and how you''re getting home after dark.'),
('light-a-single-candle','Light a Single Candle','On the next properly dark, properly cold, or just heavy evening, kill every overhead light, light one candle, and sit with it for 15 minutes. Tea or a record optional. Phone in another room, non-optional.','A pure cozy reset that needs nothing but one candle and the dark. The kind of small ritual that makes a season feel like it belongs to you.','Seasonal, nocturnal & golden-hour',1,'solo',30,0,0,0,'GBP',2,true,ARRAY['cozy','nocturnal','reflective','homebody','seasonal'],'reflection — how did you feel after the 15 minutes?','Keep the candle away from anything flammable and don''t leave it burning unattended or fall asleep with it lit.'),
('decorate-for-the-season-tonight','Decorate for the Season Tonight','Mark the season changing in your space tonight — fairy lights up, a pumpkin on the step, fresh blossom in a jam jar, the first proper blanket out of storage. One small thing that says ''it''s THIS time of year now''.','Tiny seasonal markers in your home rewire how the whole stretch of weeks feels. Cheap, fast, and your future self walking in the door will thank you.','Seasonal, nocturnal & golden-hour',1,'either',30,1,1,15,'GBP',1,true,ARRAY['seasonal','cozy','creative','homebody','nostalgic'],'photo of your one seasonal touch',NULL)
